globalThis.__BQ = {"ksilem":{"ilkokul":{"kolay":[{"q":"Ksilem bitkide hangi maddeyi taşır?","steps":[{"t":"İletim borusu","a":"Ksilem bir iletim dokusudur","d":"Ksilem, bitki gövdesi içinde uzanan ince borulardan oluşur. Bu borular, suyun bitkinin bir bölgesinden başka bir bölgesine ulaşmasını sağlar."},{"t":"Taşınan madde","a":"Su ve mineraller","d":"Ksilem, kökten alınan suyu ve suda çözünmüş madensel tuzları (mineralleri) yukarıya taşır. Böylece yapraklar ihtiyaç duydukları suya kavuşur."}],"ans":"Su ve suda çözünmüş mineralleri taşır."},{"q":"Ksilem suyu hangi yönde taşır?","steps":[{"t":"Suyun başladığı yer","a":"Su kökten alınır","d":"Bitki suyu topraktan kökleri ile emer. Bu su önce köke girer, sonra gövdeye geçer."},{"t":"Suyun gittiği yer","a":"Yukarı, yapraklara doğru","d":"Ksilem suyu kökten yukarıya, yapraklara doğru taşır. Yani taşıma tek yönlüdür ve aşağıdan yukarıya olur."}],"ans":"Kökten yapraklara doğru, yani yukarı yönde taşır."},{"q":"Ksilem su taşımanın yanında bitkiye başka ne sağlar?","steps":[{"t":"Borunun çeperi","a":"Çeperler serttir","d":"Ksilem borularının çevresindeki çeperler kalın ve serttir. Bu sertlik boruların kolayca ezilmesini engeller."},{"t":"İkinci görev","a":"Destek olur","d":"Sert çeperli ksilem boruları bitkiyi dik tutmaya yardım eder. Yani ksilem hem su taşır hem de bitkiye destek sağlar."}],"ans":"Bitkiye destek (dik durma) sağlar."},{"q":"Su ksilem ile en çok nereye ulaştırılır?","steps":[{"t":"Suyu kullanan organ","a":"Yapraklar suya ihtiyaç duyar","d":"Yapraklar besin üretmek ve serinlemek için bol su kullanır. Bu yüzden suyun yapraklara ulaşması gerekir."},{"t":"Ksilemin görevi","a":"Suyu yaprağa götürür","d":"Ksilem boruları gövde boyunca uzanıp yaprağa kadar gider. Böylece su en çok yapraklara ulaştırılmış olur."}],"ans":"Yapraklara ulaştırılır."},{"q":"Ksilem boruları bitkinin hangi bölümlerinde bulunur?","steps":[{"t":"Borunun yolu","a":"Boru baştan sona uzanır","d":"Ksilem boruları kesintisiz bir yol gibi bitkinin içinde uzanır. Bu yol suyun her yere ulaşmasını sağlar."},{"t":"Bulunduğu yerler","a":"Kök, gövde ve yaprak","d":"Ksilem kökten başlar, gövdeden geçer ve yapraklara kadar devam eder. Yani bitkinin üç ana bölümünde de bulunur."}],"ans":"Kök, gövde ve yapraklarda bulunur."}],"zor":[{"q":"Su köke girdikten sonra yapraklara ulaşana kadar hangi yolu izler?","steps":[{"t":"Başlangıç","a":"Su kökte","d":"Su önce kök kıllarıyla topraktan emilir ve köke girer. Buradan iletim dokusuna doğru ilerler."},{"t":"Boruya geçiş","a":"Su ksileme girer","d":"Kökten gelen su ksilem borularına aktarılır. Bu borular suyu yukarı taşıyacak yapıdadır."},{"t":"Varış","a":"Yapraklara çıkar","d":"Su ksilem içinde gövdeyi geçip yapraklara ulaşır. Böylece su tüm yolu tamamlamış olur."}],"ans":"Kök kılı → kök → ksilem → gövde → yaprak yolunu izler."},{"q":"Bir bitkinin ksilemi tıkanırsa yapraklarda ne olur?","steps":[{"t":"Ksilemin işi","a":"Su taşır","d":"Ksilem suyu yapraklara taşıyan borudur. Bu boru çalışmazsa su yukarı çıkamaz."},{"t":"Tıkanmanın sonucu","a":"Su yaprağa gitmez","d":"Ksilem tıkanırsa yapraklara su ulaşamaz. Su olmadan yaprak hücreleri ihtiyacını karşılayamaz."},{"t":"Yaprakta görülen","a":"Solma olur","d":"Susuz kalan yapraklar pörsüyüp solar. Çünkü su yaprağın diri ve gergin durmasını sağlar."}],"ans":"Yapraklar susuz kalır ve solar."},{"q":"Ksilem boruları olgunlaştığında neden içleri boş bir kanal gibi olur?","steps":[{"t":"Hücrenin durumu","a":"Hücreler ölür","d":"Ksilem hücreleri olgunlaştığında canlılıklarını yitirir ve ölür. Geriye yalnızca sert çeperleri kalır."},{"t":"İçin boşalması","a":"İç madde kalmaz","d":"Hücre ölünce içindeki canlı madde kaybolur ve içi boşalır. Böylece boru gibi açık bir kanal oluşur."},{"t":"Yararı","a":"Su kolay akar","d":"İçi boş kanaldan su hiçbir engele takılmadan kolayca akar. Bu, su taşımayı hızlandırır."}],"ans":"Hücreler öldüğü için içleri boşalır ve su akan boş bir kanal oluşur."},{"q":"Geniş ve dar ksilem borularından hangisi suyu daha kolay taşır, neden?","steps":[{"t":"İki tür boru","a":"Geniş ve dar borular var","d":"Ksilemde geniş borular ve dar borular bulunur. Genişlik suyun akışını etkiler."},{"t":"Genişliğin etkisi","a":"Geniş boruda su rahat akar","d":"Geniş borunun içinden daha çok su geçebilir ve su daha az engelle karşılaşır. Bu yüzden geniş boru suyu daha kolay taşır."}],"ans":"Geniş borular suyu daha kolay ve hızlı taşır çünkü içinden daha çok su geçer."},{"q":"Ksilem hem su taşıyıp hem destek sağlayabildiğine göre çeperinde nasıl bir madde olmalıdır?","steps":[{"t":"Destek ihtiyacı","a":"Sert madde gerekir","d":"Bir borunun bitkiyi dik tutması için çeperinin sert olması gerekir. Yumuşak boru bitkiyi destekleyemez."},{"t":"Çeperdeki madde","a":"Sertleştirici madde var","d":"Ksilem çeperinde onu sertleştiren özel bir madde bulunur. Bu madde sayesinde boru hem sağlam durur hem de su sızdırmaz."}],"ans":"Çeperinde onu sertleştiren bir madde (lignin) bulunmalıdır."}]},"ortaokul":{"kolay":[{"q":"Ksilem ile floem arasındaki temel görev farkı nedir?","steps":[{"t":"Ksilemin görevi","a":"Su taşır","d":"Ksilem, kökten alınan suyu ve mineralleri yapraklara taşır. Taşıması yukarı yönlüdür."},{"t":"Floemin görevi","a":"Besin taşır","d":"Floem ise yapraklarda üretilen besini bitkinin her yerine taşır. Böylece iki doku farklı maddeleri taşır."}],"ans":"Ksilem su ve mineral, floem ise besin taşır."},{"q":"Ksilem hücreleri olgunlukta canlı mıdır?","steps":[{"t":"Olgunlaşma","a":"Hücreler ölür","d":"Ksilem hücreleri olgunlaştıklarında ölürler. Geriye yalnızca sert çeperleri kalır."},{"t":"Sonuç","a":"Cansız boru","d":"Ölü hücrelerin oluşturduğu içi boş borulardan su rahatça akar. Yani olgun ksilem cansız bir yapıdır."}],"ans":"Hayır, olgun ksilem hücreleri cansızdır (ölüdür)."},{"q":"Ksilemin iki ana eleman türü nedir?","steps":[{"t":"İlk eleman","a":"Trake","d":"Trake elemanları geniş ve kısa borulardır. Uç uca eklenerek geniş su kanalları oluşturur."},{"t":"İkinci eleman","a":"Trakeit","d":"Trakeit elemanları dar ve uzundur. Bunlar da su taşır ama daha incedir."}],"ans":"Trake (geniş, kısa) ve trakeit (dar, uzun) elemanları."},{"q":"Ksilem suyu hangi kuvvet sayesinde yapraklara taşır görevini neden tek yönlü yapar?","steps":[{"t":"Suyun kaynağı","a":"Su kökten gelir","d":"Bitkinin suyu hep topraktan, kökler yoluyla alınır. Bu nedenle su her zaman alttan başlar."},{"t":"Taşıma yönü","a":"Yalnızca yukarı","d":"Ksilem suyu kökten yapraklara, yani yukarı taşır; geri taşımaz. Bu yüzden ksilemde taşıma tek yönlüdür."}],"ans":"Su hep kökten yaprağa (yukarı) gittiği için taşıma tek yönlüdür."},{"q":"Ksilem çeperini sertleştiren madde hangisidir?","steps":[{"t":"Çeperin özelliği","a":"Sert ve dayanıklı","d":"Ksilem çeperi sert ve dayanıklıdır. Bu özellik ona destek görevi kazandırır."},{"t":"Sertleştiren madde","a":"Lignin","d":"Çeperde biriken lignin maddesi onu odunlaştırıp sertleştirir. Bu sayede ksilem hem su sızdırmaz hem de bitkiyi destekler."}],"ans":"Lignin maddesidir."}],"zor":[{"q":"Bir ağacın gövdesindeki odun kısmı esas olarak hangi dokudan oluşur ve neden serttir?","steps":[{"t":"Odunun yapısı","a":"Odun ksilemdir","d":"Ağaç gövdesindeki odun, yıllar içinde biriken ksilem dokusudur. Yani odun aslında çok sayıda ksilem borusudur."},{"t":"Sertliğin nedeni","a":"Lignin biriktirilir","d":"Ksilem çeperlerinde bol lignin biriktiği için doku odunlaşır ve sertleşir. Bu birikim ağaca dayanıklılık ve destek kazandırır."}],"ans":"Odun ksilem dokusudur; çeperlerinde lignin biriktiği için serttir."},{"q":"Ksilem hücrelerinin olgunlukta ölü olması su taşıma açısından neden bir avantajdır?","steps":[{"t":"Ölü hücre","a":"İçi boştur","d":"Ölü ksilem hücresinin içinde sitoplazma ve çekirdek kalmaz; içi tamamen boşalır. Geriye yalnızca sert çeper kalır."},{"t":"Suya etkisi","a":"Engel azalır","d":"İçi boş borudan su, canlı içeriğe takılmadan akar. Böylece su uzun mesafeleri hızlı ve kolayca kat eder."},{"t":"Sonuç","a":"Verimli taşıma","d":"Engelsiz boş kanal, suyun yapraklara kadar kesintisiz ulaşmasını sağlar. Bu da su taşımayı çok verimli kılar."}],"ans":"İçleri boşaldığı için su engelsiz ve hızlı akar; bu da taşımayı verimli kılar."},{"q":"Trake ve trakeit elemanlarını yapı bakımından karşılaştırınız.","steps":[{"t":"Trake","a":"Geniş ve kısa","d":"Trake elemanları geniş çaplı ve kısa hücrelerdir. Uçları büyük gözeneklerle açık olduğu için su bol miktarda akar."},{"t":"Trakeit","a":"Dar ve uzun","d":"Trakeit elemanları ince çaplı ve uzun hücrelerdir. Suyu daha yavaş taşır ama bitkiye fazladan destek verir."},{"t":"Ortak yön","a":"İkisi de ölü","d":"Her iki eleman da olgunlukta ölü ve ligninli çeperlidir. İkisi birlikte ksilemin su iletim sistemini oluşturur."}],"ans":"Trake geniş-kısa, trakeit dar-uzundur; ikisi de olgunlukta ölü ve ligninli çeperlidir."},{"q":"Su, kökten yaprağa kadar yükselirken ksilemde hangi sırayı izler?","steps":[{"t":"Kökte emilim","a":"Su kök kılıyla alınır","d":"Su, topraktan kök kılları yoluyla emilir ve kök hücrelerine geçer. Buradan kökteki ksileme aktarılır."},{"t":"Gövdede yükselme","a":"Ksilemde yukarı çıkar","d":"Su, kökteki ksilemden gövdedeki ksileme geçerek yukarı doğru yükselir. Boş borular bu yükselmeyi kolaylaştırır."},{"t":"Yaprağa varış","a":"Yaprak ksilemine ulaşır","d":"Su, gövdeden yaprak damarlarındaki ksileme ulaşır. Buradan yaprak hücrelerine dağıtılır."}],"ans":"Kök → kök ksilemi → gövde ksilemi → yaprak ksilemi → yaprak hücreleri sırasını izler."},{"q":"Bir bitkinin gövdesinin alt kısmındaki ksilem halkası bir kuşak şeklinde çıkarılırsa bitki neden zarar görmez ama floem çıkarılırsa görür?","steps":[{"t":"Ksilemin yeri","a":"Daha içte","d":"Ksilem gövdede daha içte, odun kısmında yer alır. Yüzeydeki bir kuşak alındığında çoğu su yine de yükselebilir."},{"t":"Su taşıma sürer","a":"Yukarı su gider","d":"Ksilem su taşıdığı için yapraklar bir süre daha su alabilir. Bu yüzden bitki hemen ölmez."},{"t":"Floem farkı","a":"Floem dışta ve hayati","d":"Floem ise gövdenin dış kabuğundadır; halka biçiminde çıkarılırsa besin köke inemez. Kök beslenemediği için bitki zamanla zarar görür."}],"ans":"Ksilem içte olup suyu yukarı taşımayı sürdürebilir; floem dışta olduğu için kuşak alınınca besin köke inemez ve bitki zarar görür."}]},"lise":{"kolay":[{"q":"Ksilemin bitkideki temel iki işlevi nedir?","steps":[{"t":"Birincil işlev","a":"Su ve mineral iletimi","d":"Ksilem, kökten alınan suyu ve suda çözünmüş mineralleri kökten yapraklara doğru taşır. Bu iletim tek yönlüdür (yukarı)."},{"t":"İkincil işlev","a":"Mekanik destek","d":"Ligninli ve kalın çeperli ksilem hücreleri bitkiye mekanik destek sağlar. Özellikle odunsu bitkilerde gövdenin dik durmasını sağlar."}],"ans":"Su-mineral iletimi (yukarı) ve mekanik destek sağlamaktır."},{"q":"Ksilem hücreleri olgunlukta neden ölüdür ve bu durum işleve nasıl katkı sağlar?","steps":[{"t":"Olgunlaşma süreci","a":"Protoplast kaybolur","d":"Ksilem hücreleri olgunlaşırken çekirdek ve sitoplazma gibi canlı içerik (protoplast) kaybolur. Geriye yalnızca ligninleşmiş çeper kalır."},{"t":"İşleve katkı","a":"Engelsiz akış","d":"İçi boşalan hücrelerden su, canlı içeriğe çarpmadan akar. Bu da düşük dirençle hızlı su iletimini sağlar."}],"ans":"Protoplast kaybolup içleri boşaldığı için ölüdürler; bu, düşük dirençli ve hızlı su iletimi sağlar."},{"q":"Trake elemanlarını trakeitlerden ayıran temel yapısal özellik nedir?","steps":[{"t":"Trake","a":"Geniş, kısa, perfore","d":"Trake elemanları geniş çaplı ve kısa hücrelerdir; uçlarında perforasyon levhası denen delikli bölgeler bulunur. Bu sayede su bol ve hızlı akar."},{"t":"Trakeit","a":"Dar, uzun, geçitli","d":"Trakeitler dar ve uzun hücrelerdir; uçları açık değildir, su geçitler aracılığıyla aktarılır. Bu yüzden iletim daha yavaştır."}],"ans":"Trake geniş-kısa ve perforasyon levhalı; trakeit dar-uzun ve geçitlerle bağlıdır."},{"q":"Lignin maddesinin ksilem için önemi nedir?","steps":[{"t":"Çepere etkisi","a":"Sertleştirir","d":"Lignin, ksilem hücre çeperinde birikerek çeperi sertleştirir ve su geçirmez hale getirir. Bu, çeperin basınç altında çökmesini engeller."},{"t":"İşlevsel sonuç","a":"Destek ve dayanıklılık","d":"Ligninleşme sayesinde ksilem hem su iletim borusu olarak görev yapar hem de bitkiye mekanik destek sağlar. Bu özellik odunsu yapının temelidir."}],"ans":"Çeperi sertleştirip su geçirmez yapar; destek sağlar ve borunun çökmesini engeller."},{"q":"Ksilemde su iletimi neden tek yönlüdür?","steps":[{"t":"Kaynak ve hedef","a":"Kökten yaprağa","d":"Su daima kökten alınır ve yapraklara doğru hareket eder. Yani kaynak hep alttadır, hedef hep üsttedir."},{"t":"Yön","a":"Yalnızca yukarı","d":"Bu nedenle ksilemdeki net hareket kökten yaprağa, yani yukarı yöndedir. Floemdeki çift yönlü taşımanın aksine ksilem taşıması tek yönlüdür."}],"ans":"Su daima kökten yaprağa (yukarı) hareket ettiği için tek yönlüdür."},{"q":"Ksilemin bir bitkideki dağılımı nasıldır?","steps":[{"t":"Sürekli sistem","a":"Bütün organlarda","d":"Ksilem; kök, gövde ve yapraklarda kesintisiz bir iletim sistemi oluşturur. Bu süreklilik suyun her yere ulaşmasını sağlar."},{"t":"Damarlar","a":"İletim demetleri","d":"Ksilem, floemle birlikte iletim demetleri içinde bulunur. Yaprak damarları da bu demetlerin uzantısıdır."}],"ans":"Kök, gövde ve yapraklarda iletim demetleri içinde kesintisiz olarak bulunur."},{"q":"Ksilem ve floem birlikte nasıl bir yapı oluşturur?","steps":[{"t":"İletim demeti","a":"Birlikte bulunurlar","d":"Ksilem ve floem genellikle yan yana gelerek iletim demeti (damar) oluşturur. Bu demetler kök, gövde ve yaprakta bulunur."},{"t":"Konumları","a":"İçte ksilem, dışta floem","d":"Çoğu bitkide ksilem demetin iç tarafında, floem dış tarafında yer alır. Bu düzen iletim sistemini düzenli kılar."}],"ans":"Birlikte iletim demeti (damar) oluştururlar; genelde içte ksilem, dışta floem bulunur."},{"q":"Ksilemde su taşımayı destekleyen kohezyon kuvveti nedir?","steps":[{"t":"Su molekülleri","a":"Birbirini çeker","d":"Su molekülleri birbirine hidrojen bağları ile tutunur; bu çekime kohezyon denir. Bu sayede su molekülleri bir zincir gibi davranır."},{"t":"Taşımaya etkisi","a":"Su sütunu kopmaz","d":"Kohezyon, ksilemdeki su sütununun bütünlüğünü korur ve kopmadan yukarı çekilmesini sağlar. Böylece su yaprağa kadar kesintisiz yükselir."}],"ans":"Su moleküllerinin birbirine tutunması (kohezyon), su sütununun kopmadan yükselmesini sağlar."},{"q":"Terleme (transpirasyon) ksilemdeki su iletimini nasıl etkiler?","steps":[{"t":"Yaprakta su kaybı","a":"Su buharlaşır","d":"Yapraklardaki gözeneklerden (stoma) su buharı dışarı verilir; buna terleme denir. Bu su kaybı yaprakta bir çekme kuvveti yaratır."},{"t":"Çekme etkisi","a":"Su yukarı çekilir","d":"Terleme ile oluşan çekme, ksilemdeki su sütununu kökten yaprağa doğru yukarı çeker. Böylece terleme su iletimini sürükleyen ana kuvvettir."}],"ans":"Terleme yaprakta çekme kuvveti oluşturur ve ksilemdeki suyu yukarı doğru çeker."},{"q":"Ksilem hücrelerinin kalın çeperli olması neden gereklidir?","steps":[{"t":"Basınç sorunu","a":"Su çekilirken gerilim oluşur","d":"Su terleme ile çekilirken ksilem içinde negatif basınç (gerilim) oluşur. Bu gerilim boruyu içe doğru çökertmeye çalışır."},{"t":"Kalın çeperin rolü","a":"Çökmeyi önler","d":"Ligninli ve kalın çeperler boruyu sağlam tutar ve gerilim altında çökmesini engeller. Böylece su iletimi kesintisiz sürer."}],"ans":"Su çekilirken oluşan gerilime karşı borunun çökmesini önlemek için kalın çeper gereklidir."},{"q":"Bitkide kök basıncı ksilem iletimine nasıl katkı sağlar?","steps":[{"t":"Köke su girişi","a":"Mineral birikimi su çeker","d":"Kök hücreleri toprak suyundan mineral biriktirir; bu da osmozla köke su girişini artırır. Köke biriken su basınç oluşturur."},{"t":"Suyu itme","a":"Aşağıdan yukarı iter","d":"Kök basıncı, ksilemdeki suyu gövdeye doğru aşağıdan yukarı iter. Bu etki özellikle terlemenin az olduğu durumlarda iletime yardımcı olur."}],"ans":"Kök basıncı ksilemdeki suyu aşağıdan yukarı iterek iletime katkı sağlar."},{"q":"Yaprak damarlarındaki ksilemin işlevi nedir?","steps":[{"t":"Damarların yapısı","a":"İletim demetlerini taşır","d":"Yaprak damarları, gövdeden gelen iletim demetlerinin yaprak içindeki uzantısıdır. İçlerinde ksilem ve floem bulunur."},{"t":"Ksilemin görevi","a":"Suyu dağıtır","d":"Yaprak damarlarındaki ksilem, gövdeden gelen suyu yaprak hücrelerine dağıtır. Böylece fotosentez için gerekli su sağlanmış olur."}],"ans":"Gövdeden gelen suyu yaprak hücrelerine dağıtarak fotosentez için su sağlar."},{"q":"Ksilem neden floeme göre suyu daha hızlı taşır?","steps":[{"t":"Ksilem yapısı","a":"Ölü, boş borular","d":"Ksilem hücreleri ölü ve içi boş olduğundan su, canlı içeriğe takılmadan akar. Bu düşük direnç hızlı akışa olanak tanır."},{"t":"Floem farkı","a":"Canlı hücreler","d":"Floem ise canlı hücrelerden oluşur ve içlerinde sitoplazma vardır. Bu da floemdeki taşımayı ksileme göre yavaşlatır."}],"ans":"Ksilem ölü ve içi boş borulardan oluştuğu için düşük dirençle suyu floemden daha hızlı taşır."},{"q":"Çekme-kohezyon-gerilim kuramına göre su ksilemde nasıl yükselir?","steps":[{"t":"Çekme","a":"Terleme çeker","d":"Yapraktan terleme ile su kaybedilince yaprakta bir çekme (transpirasyon çekimi) oluşur. Bu çekme su sütununun üstünü yukarı çeker."},{"t":"Kohezyon","a":"Su sütunu bütündür","d":"Su molekülleri kohezyonla birbirine tutunduğu için sütun kopmadan yukarı taşınır. Adezyon ise sütunu çepere tutturur."},{"t":"Gerilim","a":"Negatif basınç","d":"Çekme nedeniyle su sütununda gerilim (negatif basınç) oluşur ve bu, kökteki suyu yukarı çeker. Böylece su tüm bitki boyunca yükselir."}],"ans":"Terleme çekmesi, su moleküllerinin kohezyonu ve oluşan gerilim sayesinde su sütunu kökten yaprağa yükselir."},{"q":"Odunsu bitkilerde her yıl yeni ksilem üreten doku hangisidir?","steps":[{"t":"Kambiyum","a":"Bölünür doku","d":"Gövdede ksilem ve floem arasında kambiyum adı verilen bölünür (meristem) doku bulunur. Bu doku sürekli bölünerek yeni hücreler üretir."},{"t":"Yeni ksilem","a":"İçe doğru","d":"Kambiyum içe doğru yeni ksilem (odun), dışa doğru yeni floem üretir. Her yıl üretilen ksilem yıllık halkaları oluşturur."}],"ans":"Kambiyum (vasküler kambiyum) içe doğru her yıl yeni ksilem üretir."}],"zor":[{"q":"Çekme-kohezyon-gerilim kuramında adezyon kuvvetinin rolü nedir ve kohezyondan farkı nedir?","steps":[{"t":"Kohezyon","a":"Su-su çekimi","d":"Kohezyon, su moleküllerinin birbirine hidrojen bağı ile tutunmasıdır. Bu, su sütununun kopmadan bütün kalmasını sağlar."},{"t":"Adezyon","a":"Su-çeper çekimi","d":"Adezyon ise su moleküllerinin ksilem çeperine tutunmasıdır. Bu kuvvet su sütununun çepere yapışıp aşağı kaymasını engeller."},{"t":"Birlikte etki","a":"Sütun korunur","d":"Kohezyon sütunun iç bütünlüğünü, adezyon ise sütunun çepere bağlılığını sağlar. İkisi birlikte su sütununun gerilim altında kopmadan yükselmesine olanak tanır."}],"ans":"Adezyon suyun çepere tutunmasıdır; kohezyon su-su çekimidir. Adezyon sütunun kaymasını, kohezyon kopmasını engeller."},{"q":"Bir ağacın gövdesinde halkalı kabuk soyma (girdle) yapıldığında ksilem işlevini bir süre sürdürebilirken bitkinin neden öldüğünü açıklayınız.","steps":[{"t":"Soyulan doku","a":"Floem alınır","d":"Halkalı kabuk soymada gövdenin dış kısmındaki floem ve kambiyum bir kuşak halinde uzaklaştırılır. Ksilem içte kaldığı için zarar görmez."},{"t":"Su iletimi sürer","a":"Yapraklar su alır","d":"İçteki ksilem suyu yukarı taşımaya devam ettiği için yapraklar bir süre canlı kalır ve fotosentez yapar. Bu nedenle bitki hemen ölmez."},{"t":"Kök açlığı","a":"Besin inemez","d":"Floem kesildiği için yapraklarda üretilen besin köke taşınamaz. Kökler aç kalıp ölünce su alımı durur ve sonunda bitki ölür."}],"ans":"Ksilem içte kalıp su iletimini sürdürür; ancak floem kesildiği için besin köke inemez, kök açlıktan ölünce su alımı durur ve bitki ölür."},{"q":"Ksilemde kavitasyon (hava kabarcığı oluşumu) nedir ve su iletimini nasıl etkiler?","steps":[{"t":"Gerilim ve kavitasyon","a":"Su sütunu kopar","d":"Aşırı terleme ya da kuraklıkta ksilemdeki gerilim çok artar ve su sütununda hava kabarcığı (kavitasyon) oluşur. Bu kabarcık su sütununun bütünlüğünü bozar."},{"t":"Emboli","a":"Boru tıkanır","d":"Oluşan hava kabarcığı boruyu doldurarak su akışını engeller; buna emboli denir. Embolili boru artık su taşıyamaz."},{"t":"Bitkinin önlemi","a":"Yan geçitlerle aşar","d":"Bitki, suyu komşu borulara geçitler aracılığıyla yönlendirerek tıkalı boruyu atlar. Bazı bitkiler kök basıncıyla kabarcığı eritip iletimi onarabilir."}],"ans":"Kavitasyon, gerilim altında su sütununda hava kabarcığı oluşmasıdır; bu emboliye yol açıp boruyu tıkar, su iletimini durdurur."},{"q":"Birincil ksilem ile ikincil ksilem arasındaki fark nedir ve hangisi yıllık halkaları oluşturur?","steps":[{"t":"Birincil ksilem","a":"Uç meristemden","d":"Birincil ksilem, gövde ve kökün uç (apikal) meristeminden gelişir ve bitkinin ilk boyca uzamasında oluşur. Genç ve ince yapılarda bulunur."},{"t":"İkincil ksilem","a":"Kambiyumdan","d":"İkincil ksilem, vasküler kambiyumun içe doğru bölünmesiyle oluşur ve gövdenin enine kalınlaşmasını sağlar. Bu, odunsu bitkilerin odununu meydana getirir."},{"t":"Yıllık halka","a":"İkincil ksilem","d":"İkincil ksilem her yıl yeniden üretilerek yaz ve ilkbahar odunu farklarıyla yıllık halkaları oluşturur. Bu halkalar ağacın yaşının belirlenmesinde kullanılır."}],"ans":"Birincil ksilem uç meristemden (boyca uzama), ikincil ksilem kambiyumdan (enine kalınlaşma) oluşur; yıllık halkaları ikincil ksilem oluşturur."},{"q":"Kök basıncı ile gutasyon (damlama) olayı arasındaki ilişkiyi açıklayınız.","steps":[{"t":"Kök basıncı","a":"Su yukarı itilir","d":"Geceleri terleme azaldığında kök hücreleri mineral biriktirerek osmozla su çeker ve ksilemde kök basıncı oluşturur. Bu basınç suyu yukarı iter."},{"t":"Su fazlası","a":"Yaprağa birikir","d":"Terleme yok denecek kadar azken yükselen su yaprakta birikir ve dışarı atılması gerekir. Bu fazla su yaprak kenarındaki özel açıklıklara yönlenir."},{"t":"Gutasyon","a":"Su damlaları","d":"Yaprak kenarındaki hidatot adı verilen açıklıklardan sıvı su damlaları halinde dışarı atılır; buna gutasyon denir. Bu olay kök basıncının doğrudan kanıtıdır."}],"ans":"Kök basıncı, terlemenin azaldığı durumlarda suyu yukarı iter; fazla su hidatotlardan damla halinde atılır (gutasyon). Yani gutasyon kök basıncının kanıtıdır."},{"q":"Ksilemin destek işlevi ile floemin destek işlevinin yokluğu, bitki dik durmasını nasıl açıklar?","steps":[{"t":"Ksilem çeperi","a":"Ligninli ve sert","d":"Ksilem çeperleri lignin birikimi ile sertleşmiş ve odunlaşmıştır. Bu sert yapı mekanik destek sağlamaya elverişlidir."},{"t":"Floem yapısı","a":"İnce çeperli, canlı","d":"Floem hücreleri canlı ve genelde ince çeperlidir; lignin içermez. Bu yapı destek için uygun değildir."},{"t":"Sonuç","a":"Destek ksilemden","d":"Bu nedenle bitkinin dik durmasını sağlayan asıl mekanik destek ksilemden (özellikle ikincil ksilem/odun) gelir. Floem yalnızca besin iletiminde uzmanlaşmıştır."}],"ans":"Ligninli sert ksilem mekanik destek sağlarken, ince çeperli floem destek vermez; bu yüzden bitkinin dik durması ksileme dayanır."},{"q":"Terleme çekimi neden ksilemde su yükselmesinin en güçlü itici gücü kabul edilir?","steps":[{"t":"Diğer kuvvetler","a":"Kök basıncı sınırlı","d":"Kök basıncı yalnızca terlemenin düşük olduğu durumlarda ve sınırlı yükseklikte etkili olur. Yüksek ağaçlarda tek başına yetersiz kalır."},{"t":"Terleme çekimi","a":"Sürekli ve güçlü","d":"Yapraklardan sürekli su kaybı, ksilemde güçlü ve kalıcı bir negatif basınç (çekme) oluşturur. Bu çekme on metrelerce su sütununu yukarı taşıyabilir."},{"t":"Sonuç","a":"Ana itici güç","d":"Kohezyon-gerilim mekanizması ile birleşen terleme çekimi, çok yüksek ağaçlarda bile suyu tepeye taşıyabildiği için ana itici güç sayılır. Kök basıncı yalnızca yardımcı roldedir."}],"ans":"Terleme çekimi sürekli ve çok güçlü bir negatif basınç oluşturup yüksek ağaçlarda bile suyu taşıyabildiği için en güçlü itici güç kabul edilir."},{"q":"Trakeitlerin hem iletim hem destek görevi görmesine karşılık trakelerin daha çok iletime özelleşmesini yapılarıyla açıklayınız.","steps":[{"t":"Trakeit yapısı","a":"Dar, uzun, kalın çeper","d":"Trakeitler dar ve uzun olup nispeten kalın ligninli çeperlere sahiptir. Bu kalın çeper hem destek hem dar bir su yolu sağlar."},{"t":"Trake yapısı","a":"Geniş, perforasyonlu","d":"Trakeler geniş çaplı ve uçları büyük perforasyon levhalarıyla açıktır. Geniş ve açık yapı yüksek hızda su iletimine elverişlidir ama destek katkısı görece azdır."},{"t":"Sonuç","a":"İşbölümü","d":"Bu nedenle trakeit dar yapısıyla destek-iletim dengesini korurken, trake geniş ve açık yapısıyla iletim verimini en üst düzeye çıkarır. Gelişmiş bitkilerde trake iletime özelleşmiştir."}],"ans":"Dar ve kalın çeperli trakeit hem destek hem iletim yapar; geniş ve perforasyonlu trake yüksek hızlı iletime özelleştiği için destek katkısı azdır."},{"q":"Bir ksilem borusunda suyun sürekli (kesintisiz) bir sütun halinde kalması neden kritik öneme sahiptir?","steps":[{"t":"Sütun bütünlüğü","a":"Çekim iletilir","d":"Su sütunu kesintisiz olduğunda yapraktaki çekme kuvveti zincir gibi köke kadar iletilir. Böylece tüm sütun aynı anda yukarı çekilir."},{"t":"Kopmanın sonucu","a":"İletim durur","d":"Sütunda hava kabarcığı oluşup kopma (kavitasyon) olursa çekme iletilemez ve o boruda su yükselmesi durur. Bu, yaprağın susuz kalmasına yol açabilir."},{"t":"Kohezyonun rolü","a":"Sütunu korur","d":"Su moleküllerinin kohezyonu sütunun kopmadan bütün kalmasını sağlar. Bu sayede çekim mekanizması güvenilir biçimde çalışır."}],"ans":"Kesintisiz sütun, yapraktaki çekme kuvvetinin köke kadar iletilmesini sağlar; kopma olursa o boruda iletim durur."},{"q":"İlkbahar odunu (erken odun) ile yaz odunu (geç odun) arasındaki fark yıllık halkaları nasıl oluşturur?","steps":[{"t":"İlkbahar odunu","a":"Geniş, açık renkli","d":"İlkbaharda su bol ve büyüme hızlı olduğundan geniş çaplı, ince çeperli ksilem hücreleri üretilir. Bu doku açık renkli ve gevşek görünür."},{"t":"Yaz odunu","a":"Dar, koyu renkli","d":"Yaza doğru büyüme yavaşladığında dar çaplı, kalın çeperli hücreler oluşur. Bu doku daha yoğun ve koyu renklidir."},{"t":"Yıllık halka","a":"Renk geçişi","d":"Açık ilkbahar odunundan koyu yaz oduna geçiş belirgin bir sınır oluşturur ve her yıl bir halka meydana gelir. Bu halkalar sayılarak ağacın yaşı belirlenebilir."}],"ans":"İlkbaharda geniş-açık renkli, yazın dar-koyu renkli ksilem üretilir; bu renk geçişi her yıl bir yıllık halka oluşturur."},{"q":"Yüksek bir ağaçta suyu tepeye taşımak için neden tek bir mekanizma yeterli değildir?","steps":[{"t":"Kök basıncının sınırı","a":"Az metre kaldırır","d":"Kök basıncı yalnızca birkaç metre yüksekliğe kadar su itebilir ve terleme yüksekken etkisizleşir. Bu yüzden tek başına yüksek ağaca yetmez."},{"t":"Terleme çekiminin gücü","a":"Sürükleyici güç","d":"Terleme çekimi kohezyon-gerilim ile birlikte suyu on metrelerce yukarı taşıyabilir. Ancak kabarcık riski ve gece terlemenin azalması gibi sınırları vardır."},{"t":"Birlikte çalışma","a":"Mekanizmalar tamamlar","d":"Kök basıncı düşük terleme durumunda iletimi sürdürürken, terleme çekimi gündüz ana itici güç olur. Mekanizmalar birbirini tamamladığı için su her koşulda tepeye ulaşır."}],"ans":"Kök basıncı sınırlı, terleme çekimi koşullara bağlıdır; mekanizmalar birbirini tamamladığında su yüksek ağaçların tepesine ulaşabilir."},{"q":"Stomaların açılıp kapanması ksilemdeki su iletim hızını nasıl düzenler?","steps":[{"t":"Stoma açık","a":"Terleme artar","d":"Stomalar açıkken yapraktan su buharı çıkışı (terleme) artar ve yaprakta güçlü bir çekme oluşur. Bu çekme ksilemdeki su akışını hızlandırır."},{"t":"Stoma kapalı","a":"Terleme azalır","d":"Stomalar kapandığında su kaybı ve dolayısıyla çekme azalır. Buna bağlı olarak ksilemdeki su iletim hızı düşer."},{"t":"Düzenleme","a":"Su kaybı dengesi","d":"Bitki, su kaybı ile su alımını dengelemek için stomaları açıp kapatarak iletim hızını ayarlar. Kuraklıkta stomaları kapatıp aşırı su kaybını önler."}],"ans":"Stomalar açıkken terleme ve çekme artarak iletim hızlanır; kapandığında terleme azalır ve iletim yavaşlar, böylece su kaybı düzenlenir."},{"q":"Bir bitkinin ksilemindeki minerallerin de su ile birlikte taşınması neden mümkündür?","steps":[{"t":"Çözünme","a":"Mineraller suda çözünür","d":"Topraktaki madensel tuzlar (mineraller) suda iyonlar halinde çözünür. Böylece su ile birlikte tek bir çözelti oluştururlar."},{"t":"Pasif taşınma","a":"Su akışıyla sürüklenir","d":"Su ksilemde yukarı çekilirken içinde çözünmüş mineraller de su ile birlikte sürüklenir. Bu nedenle mineraller için ayrı bir taşıma sistemi gerekmez."},{"t":"Sonuç","a":"Tek akış","d":"Su ve mineraller aynı akış içinde yukarı taşındığı için yapraklara hem su hem de gerekli mineraller birlikte ulaşır. Bu, ksilemin verimli bir iletim sistemi olmasını sağlar."}],"ans":"Mineraller suda iyon olarak çözündüğü için su akışıyla birlikte sürüklenir; böylece su ve mineraller tek akışta yukarı taşınır."},{"q":"Halofit (tuzcul) ve kserofit (kurakçıl) bitkilerde ksilem yapısının suyu koruyacak biçimde nasıl uyarlandığı düşünülür?","steps":[{"t":"Su kıtlığı sorunu","a":"Aşırı kayıp riski","d":"Kurak ve tuzlu ortamlarda su azdır ve aşırı terleme bitki için tehlikelidir. Bu nedenle su iletim ve koruma sistemleri uyum sağlamalıdır."},{"t":"Ksilem uyarlaması","a":"Dar, güçlü borular","d":"Bu bitkilerde ksilem boruları genellikle daha dar ve kalın çeperlidir; bu, gerilim altında kavitasyon riskini azaltır. Dar borular su sütununun kopmasına karşı daha dayanıklıdır."},{"t":"Bütünsel uyum","a":"Stoma ve doku desteği","d":"Ksilem uyarlaması, az ve kalın stomalar ve su depolayan dokularla birlikte çalışır. Böylece bitki kısıtlı suyu verimli taşır ve iletim güvenliğini korur."}],"ans":"Kurak/tuzlu ortam bitkilerinde ksilem boruları daha dar ve kalın çeperlidir; bu kavitasyon riskini azaltarak kısıtlı suyun güvenli iletimini sağlar."},{"q":"Ksilem ve floemin birlikte iletim demeti oluşturmasının bitki için işlevsel avantajı nedir?","steps":[{"t":"Yan yana konum","a":"İki yön bir arada","d":"İletim demetinde ksilem (su yukarı) ve floem (besin her yöne) yan yana bulunur. Bu, su ve besin iletiminin aynı yol boyunca yürütülmesini sağlar."},{"t":"Madde alışverişi","a":"Su besin taşımayı destekler","d":"Ksilemden floeme su geçişi, floemdeki basınç-akış mekanizmasını besler. Yani iki doku birbirinin işlevini destekler."},{"t":"Sonuç","a":"Verimli dağıtım","d":"Demet yapısı, su ve besinin bitkinin tüm organlarına eşgüdümlü ve verimli dağıtılmasını sağlar. Bu da bitkinin büyümesini ve yaşamını sürdürmesini kolaylaştırır."}],"ans":"Yan yana bulunan ksilem ve floem, su ve besin iletimini eşgüdümlü yürütür; ksilemden floeme su geçişi basınç-akışı besleyerek verimli dağıtım sağlar."}]}},"floem":{"ilkokul":{"kolay":[{"q":"Floem bitkide hangi maddeyi taşır?","steps":[{"t":"İletim borusu","a":"Floem bir iletim dokusudur","d":"Floem, bitkinin içinde uzanan borulardan oluşur. Bu borular bitkinin ürettiği maddeyi taşır."},{"t":"Taşınan madde","a":"Besin (şeker)","d":"Floem, yapraklarda üretilen besini (özellikle şekeri) bitkinin her yanına taşır. Böylece tüm organlar beslenir."}],"ans":"Yapraklarda üretilen besini (şekeri) taşır."},{"q":"Floemdeki besin nerede üretilir?","steps":[{"t":"Besin üretimi","a":"Yapraklarda yapılır","d":"Bitki, besinini yapraklarında güneş ışığı yardımıyla üretir. Bu olaya fotosentez denir."},{"t":"Floemin görevi","a":"Üretilen besni taşır","d":"Yaprakta üretilen besin floem borularına aktarılır ve bitkinin her yanına dağıtılır. Yani floem besni yapraktan alıp götürür."}],"ans":"Besin yapraklarda üretilir, floem onu taşır."},{"q":"Floem besni hangi yönlerde taşıyabilir?","steps":[{"t":"Besinin gideceği yerler","a":"Her yöne","d":"Bitkinin kökü, gövdesi, çiçeği ve meyvesi besne ihtiyaç duyar. Bu organlar bitkinin hem üstünde hem altında bulunur."},{"t":"Taşıma yönü","a":"Aşağı ve yukarı","d":"Floem besni hem aşağıya köke hem de yukarıya diğer organlara taşıyabilir. Yani floemde taşıma çift yönlüdür."}],"ans":"Hem yukarı hem aşağı, yani çift yönlü taşır."},{"q":"Floem boruları canlı mıdır?","steps":[{"t":"Hücrelerin durumu","a":"Floem hücreleri canlıdır","d":"Floemi oluşturan hücreler olgunlukta bile canlı kalır. Bu, ksilemden farklı bir özelliktir."},{"t":"Sonuç","a":"Canlı boru","d":"Floem canlı hücrelerden oluştuğu için besni aktif olarak taşıyabilir. Yani floem yaşayan bir iletim dokusudur."}],"ans":"Evet, floem boruları canlıdır."},{"q":"Floemin taşıdığı besin meyvelerde ne işe yarar?","steps":[{"t":"Besin yolu","a":"Besin meyveye gider","d":"Floem, yaprakta üretilen şekeri meyvelere kadar taşır. Meyveler de besni alır."},{"t":"Meyvede etki","a":"Tatlanır ve büyür","d":"Meyveye ulaşan şeker meyvenin büyümesini ve tatlanmasını sağlar. Bu yüzden olgun meyveler tatlı olur."}],"ans":"Meyvenin büyümesini ve tatlanmasını sağlar."}],"zor":[{"q":"Yaprakta üretilen şeker köke kadar nasıl ulaşır?","steps":[{"t":"Üretim yeri","a":"Şeker yaprakta","d":"Bitki, fotosentezle yaprakta şeker üretir. Bu şekerin diğer organlara taşınması gerekir."},{"t":"Floeme yükleme","a":"Şeker floeme girer","d":"Yapraktaki şeker floem borularına aktarılır. Floem bu şekeri taşımaya hazırdır."},{"t":"Köke iniş","a":"Aşağı taşınır","d":"Floem şekeri gövde boyunca aşağıya, köke kadar taşır. Böylece kök de beslenmiş olur."}],"ans":"Yaprak → floem → gövde → kök yoluyla aşağı taşınarak ulaşır."},{"q":"Bir bitkinin floemi kesilirse köklerde ne olur?","steps":[{"t":"Floemin görevi","a":"Besni köke taşır","d":"Floem, yaprakta üretilen besni köke kadar taşır. Kök bu besinle beslenir."},{"t":"Kesilmenin sonucu","a":"Besin inemez","d":"Floem kesilirse besin aşağı, köke inemez. Kök beslenmesi durur."},{"t":"Kökte görülen","a":"Kök açlık çeker","d":"Besin alamayan kökler açlıktan zayıflar ve zamanla zarar görür. Çünkü kökler kendi besnini üretemez."}],"ans":"Besin köke inemez, kökler açlıktan zarar görür."},{"q":"Floemin canlı olması besin taşıma için neden gereklidir?","steps":[{"t":"Aktif taşıma","a":"Enerji gerekir","d":"Besni floeme yüklemek ve taşımak enerji ister. Bu işi yapacak hücrelerin canlı olması gerekir."},{"t":"Canlılığın rolü","a":"Hücreler iş yapar","d":"Canlı floem hücreleri enerji harcayarak şekeri taşıyabilir. Ölü hücreler bu işi yapamaz."}],"ans":"Besni aktif (enerji harcayarak) taşımak için hücrelerin canlı olması gerekir."},{"q":"Floemde besin neden hem aşağı hem yukarı taşınabilir?","steps":[{"t":"İhtiyaç duyan organlar","a":"Her yerde var","d":"Bitkinin kökü altta, çiçek ve genç sürgünleri üstte besne ihtiyaç duyar. Yani besin gereken organlar her iki yönde de bulunur."},{"t":"Taşıma yönü","a":"İhtiyaca göre","d":"Floem besni, ihtiyaç duyan organa doğru yani hem aşağı hem yukarı taşır. Bu yüzden floemde taşıma çift yönlüdür."}],"ans":"Besne ihtiyaç duyan organlar hem altta hem üstte olduğu için besin çift yönlü taşınır."},{"q":"Şeker depolayan bir patates yumrusuna besin nereden gelir?","steps":[{"t":"Üretim yeri","a":"Yapraklarda","d":"Patatesin yaprakları fotosentezle şeker üretir. Bu şekerin depolanması gerekir."},{"t":"Floemle taşıma","a":"Yumruya iner","d":"Floem, yaprakta üretilen şekeri toprak altındaki yumruya taşır. Yumru bir depo organıdır."},{"t":"Depolama","a":"Nişasta olur","d":"Yumruya gelen şeker burada nişasta olarak depolanır. Böylece patates besin deposu haline gelir."}],"ans":"Besin yapraklarda üretilir ve floemle yumruya taşınarak orada depolanır."}]},"ortaokul":{"kolay":[{"q":"Floem ile ksilem arasındaki temel görev farkı nedir?","steps":[{"t":"Floemin görevi","a":"Besin taşır","d":"Floem, yapraklarda üretilen besni (şeker) bitkinin her yerine taşır. Taşıması çift yönlüdür."},{"t":"Ksilemin görevi","a":"Su taşır","d":"Ksilem ise kökten alınan su ve mineralleri yapraklara taşır. Böylece iki doku farklı görev üstlenir."}],"ans":"Floem besin (şeker), ksilem ise su ve mineral taşır."},{"q":"Floemi oluşturan iki ana hücre türü nedir?","steps":[{"t":"İlk hücre","a":"Kalburlu boru","d":"Floemde besni taşıyan ana yapı kalburlu borulardır. Bu hücreler canlı olmasına rağmen çekirdeklerini kaybetmiştir."},{"t":"İkinci hücre","a":"Arkadaş hücre","d":"Kalburlu boruların yanında arkadaş (refakatçi) hücreler bulunur. Bunlar kalburlu borulara yardım eder."}],"ans":"Kalburlu borular ve arkadaş (refakatçi) hücreler."},{"q":"Floem hücreleri olgunlukta canlı mıdır?","steps":[{"t":"Hücre durumu","a":"Canlı kalırlar","d":"Floem hücreleri olgunlukta bile canlıdır. Bu, onları ölü ksilem hücrelerinden ayırır."},{"t":"Önemi","a":"Aktif taşıma","d":"Canlı olmaları sayesinde floem besni enerji harcayarak aktif olarak taşır. Bu yüzden floemin canlılığı önemlidir."}],"ans":"Evet, floem hücreleri olgunlukta canlıdır."},{"q":"Kalburlu borular neden bu adı alır?","steps":[{"t":"Hücre uçları","a":"Delikli levha var","d":"Kalburlu boru hücrelerinin uçlarında çok sayıda delik bulunan kalburlu levhalar vardır. Bu levhalar kalbura (eleğe) benzer."},{"t":"İşlevi","a":"Besin geçer","d":"Bu deliklerden besin çözeltisi bir hücreden diğerine geçer. Delikli yapısı nedeniyle bu hücrelere kalburlu boru denir."}],"ans":"Uçlarındaki delikli kalburlu levhalar nedeniyle bu adı alır."},{"q":"Arkadaş hücrelerin temel görevi nedir?","steps":[{"t":"Kalburlu borunun eksiği","a":"Çekirdeği yok","d":"Kalburlu borular çekirdeklerini kaybetmiştir ve kendi yaşamsal işlerini tam yürütemez. Bu yüzden dışarıdan desteğe ihtiyaç duyarlar."},{"t":"Arkadaş hücrenin rolü","a":"Destek verir","d":"Arkadaş hücreler çekirdekli ve canlıdır; kalburlu borunun yaşamsal işlevlerini ve besin yüklenmesini destekler. Böylece besin taşıma sürdürülür."}],"ans":"Çekirdeksiz kalburlu boruların yaşamsal işlevlerini ve besin yüklenmesini destekler."}],"zor":[{"q":"Floemde besin akışı neden çift yönlü olabilir, oysa ksilemde tek yönlüdür?","steps":[{"t":"Ksilemdeki durum","a":"Su hep kökten","d":"Ksilemde su her zaman kökten alınıp yapraklara taşınır; kaynak hep alttadır. Bu yüzden ksilem taşıması tek yönlüdür."},{"t":"Floemdeki durum","a":"Kaynak değişebilir","d":"Floemde besin kaynağı yapraktır ama besin ihtiyacı hem üstteki hem alttaki organlardadır. Kaynak ve havuz konumu değişebilir."},{"t":"Sonuç","a":"Çift yön","d":"Besin, üretildiği kaynaktan ihtiyaç duyulan havuza taşındığı için hem yukarı hem aşağı akabilir. Bu yüzden floem taşıması çift yönlüdür."}],"ans":"Ksilemde kaynak hep kök (alt) iken, floemde besin kaynaktan havuza taşınır ve havuz hem üstte hem altta olabildiği için çift yönlüdür."},{"q":"Basınç-akış (kütle akışı) mekanizmasını ana hatlarıyla açıklayınız.","steps":[{"t":"Kaynakta yükleme","a":"Şeker floeme girer","d":"Yaprak gibi kaynak bölgede şeker floeme yüklenir; bu, suyun da osmozla floeme girmesine yol açar. Böylece kaynak ucunda yüksek basınç oluşur."},{"t":"Basınç farkı","a":"Akış başlar","d":"Havuz bölgede (kök, meyve) şeker floemden alındığı için orada basınç düşer. Kaynak ile havuz arasındaki basınç farkı besin çözeltisini ittirir."},{"t":"Havuzda boşaltma","a":"Şeker havuza geçer","d":"Çözelti yüksek basınçtan düşük basınca doğru akar ve havuzda şeker hücrelere boşaltılır. Böylece besin sürekli kaynaktan havuza taşınır."}],"ans":"Kaynakta şeker yüklenip basınç artar, havuzda şeker alınıp basınç düşer; bu basınç farkı çözeltiyi kaynaktan havuza ittirir."},{"q":"Kalburlu boru ve arkadaş hücre arasındaki işbölümünü açıklayınız.","steps":[{"t":"Kalburlu boru","a":"Taşıma kanalı","d":"Kalburlu borular besin çözeltisinin aktığı ana kanaldır; çekirdeksiz oldukları için kendi metabolizmalarını tam yürütemezler. Yine de canlıdırlar."},{"t":"Arkadaş hücre","a":"Yaşam desteği","d":"Çekirdekli arkadaş hücreler kalburlu borunun yaşamsal işlevlerini yürütür ve şekerin floeme yüklenmesini sağlar. İki hücre plazmodezmlerle bağlıdır."},{"t":"Birlikte çalışma","a":"Verimli iletim","d":"Kalburlu boru iletim, arkadaş hücre destek ve yükleme görevi üstlenerek birlikte besin taşımayı verimli kılar. Bu işbölümü floem iletiminin temelidir."}],"ans":"Kalburlu boru besni taşır; çekirdekli arkadaş hücre onun yaşamsal işlevlerini yürütüp şeker yüklemesini sağlar. İkisi işbölümü yapar."},{"q":"Bir meyve olgunlaşırken floem trafiğinin yönü nasıl değişir?","steps":[{"t":"Genç dönem","a":"Yaprak kaynak","d":"Bitkide olgun yapraklar fotosentez yapıp şeker üreten kaynaklardır. Bu şeker büyüyen organlara taşınır."},{"t":"Meyve havuz","a":"Şeker çeker","d":"Olgunlaşan meyve fotosentez yapmaz; tersine bol şeker tüketip depolar, yani bir havuz olur. Floem besni meyveye doğru taşır."},{"t":"Yön","a":"Yaprağa doğru değil","d":"Bu nedenle floemde besin akışı yapraktan meyveye doğrudur. Meyve havuz olduğu sürece floem trafiği ona yönelir."}],"ans":"Olgun yaprak kaynak, olgunlaşan meyve havuz olur; floem besni yapraktan meyveye doğru taşır."},{"q":"Halkalı kabuk soyma (floem kesilmesi) sonucunda kesik üstünde neden şişkinlik oluşur?","steps":[{"t":"Floem kesilir","a":"Aşağı akış durur","d":"Halkalı soymada gövde kabuğundaki floem bir kuşak halinde kesilir. Böylece yapraktan aşağı (köke) besin akışı engellenir."},{"t":"Besin birikimi","a":"Kesik üstünde toplanır","d":"Yapraklarda üretilen besin köke inemediği için kesiğin hemen üstünde birikir. Bu bölgede şeker ve dolayısıyla su yoğunlaşır."},{"t":"Şişkinlik","a":"Doku kalınlaşır","d":"Biriken besin bu bölgede hücre büyümesini artırır ve dokular kalınlaşarak şişkinlik oluşur. Bu, floemin besni aşağı taşıdığının kanıtıdır."}],"ans":"Floem kesildiği için besin köke inemez ve kesik üstünde birikir; bu birikim dokuyu kalınlaştırarak şişkinlik oluşturur."}]},"lise":{"kolay":[{"q":"Floemin bitkideki temel işlevi nedir?","steps":[{"t":"İletim görevi","a":"Organik besin taşır","d":"Floem, fotosentezle üretilen organik besni (özellikle sakkaroz) bitkinin tüm organlarına taşır. Bu iletim kaynaktan havuza doğru gerçekleşir."},{"t":"Yön","a":"Çift yönlü","d":"Besin hem yukarıdaki hem aşağıdaki havuzlara taşınabildiği için floem iletimi çift yönlüdür. Bu, ksilemin tek yönlü iletiminden farklıdır."}],"ans":"Fotosentez ürünü organik besni (sakkaroz) kaynaktan havuza, çift yönlü taşımaktır."},{"q":"Floemde taşınan başlıca organik madde nedir?","steps":[{"t":"Fotosentez ürünü","a":"Glikoz üretilir","d":"Yapraklarda fotosentezle önce glikoz üretilir. Ancak glikoz taşıma için doğrudan en uygun biçim değildir."},{"t":"Taşıma biçimi","a":"Sakkaroz","d":"Glikoz, taşımaya daha uygun olan sakkaroza (çay şekeri) dönüştürülerek floeme yüklenir. Bu yüzden floemde başlıca taşınan organik madde sakkarozdur."}],"ans":"Başlıca sakkaroz (çözünmüş şeker) taşınır."},{"q":"Kalburlu boru elemanlarının olgunlukta çekirdeklerini kaybetmesinin işlevsel anlamı nedir?","steps":[{"t":"Çekirdek kaybı","a":"Boş iç hacim","d":"Kalburlu borular olgunlaşırken çekirdek ve birçok organel kaybolur; iç hacim büyük ölçüde boşalır. Bu, besin çözeltisinin akışına yer açar."},{"t":"İşlevsel sonuç","a":"Akış kolaylaşır","d":"İçi büyük ölçüde boşalan boruda besin çözeltisi daha az engelle akar. Bu, kütle akışını kolaylaştırır."}],"ans":"İç hacim boşalıp besin çözeltisinin akışı kolaylaştığı için çekirdek kaybı işlevseldir."},{"q":"Arkadaş (refakatçi) hücrelerin floemdeki rolü nedir?","steps":[{"t":"Yaşamsal destek","a":"Çekirdekli hücre","d":"Arkadaş hücreler çekirdekli ve organelce zengin canlı hücrelerdir. Çekirdeksiz kalburlu borunun yaşamsal metabolizmasını üstlenir."},{"t":"Yükleme","a":"Şekeri floeme verir","d":"Arkadaş hücreler şekerin kalburlu boruya yüklenmesini (aktif taşıma ile) sağlar. İki hücre plazmodezmlerle bağlı çalışır."}],"ans":"Çekirdeksiz kalburlu borunun metabolizmasını yürütür ve şeker yüklemesini sağlarlar."},{"q":"Kalburlu levha nedir ve floemdeki işlevi nedir?","steps":[{"t":"Yapı","a":"Delikli uç levha","d":"Kalburlu levha, kalburlu boru hücrelerinin uçlarındaki çok sayıda gözenek (delik) içeren bölmedir. Bu delikler hücreler arası geçişi sağlar."},{"t":"İşlev","a":"Besin geçişi","d":"Besin çözeltisi bu deliklerden bir kalburlu borudan diğerine geçer. Böylece besin sürekli bir akış kanalı boyunca taşınır."}],"ans":"Kalburlu boru uçlarındaki delikli levhadır; besin çözeltisinin hücreler arası geçişini sağlar."},{"q":"Floemde kaynak (source) ve havuz (sink) ne anlama gelir?","steps":[{"t":"Kaynak","a":"Besin üreten/depodan veren","d":"Kaynak, fotosentez yapan olgun yapraklar gibi besin üreten veya deposundan besin veren bölgedir. Buradan besin floeme yüklenir."},{"t":"Havuz","a":"Besin tüketen/depolayan","d":"Havuz; kök, meyve, genç sürgün gibi besni tüketen ya da depolayan bölgedir. Burada besin floemden boşaltılır."}],"ans":"Kaynak besni floeme veren (örn. olgun yaprak), havuz besni alan bölgedir (örn. kök, meyve)."},{"q":"Floem iletiminin neden enerji (ATP) gerektirdiği söylenir?","steps":[{"t":"Aktif yükleme","a":"Şeker pompalanır","d":"Kaynakta şekerin floeme yüklenmesi çoğu bitkide aktif taşıma ile, yani enerji harcanarak yapılır. Bu işlem ATP gerektirir."},{"t":"Canlı hücre","a":"Metabolizma sürer","d":"Floem hücreleri canlı olduğu için yaşamsal işlevlerini sürdürmek de enerji ister. Bu nedenle floem iletimi enerji harcayan aktif bir süreçtir."}],"ans":"Şekerin floeme aktif yüklenmesi ve canlı hücrelerin metabolizması ATP gerektirdiği için floem iletimi enerji ister."},{"q":"Floem hücrelerinin canlı olması ksileme göre hangi temel farkı oluşturur?","steps":[{"t":"Floem","a":"Canlı hücre","d":"Floem hücreleri olgunlukta canlıdır ve besni aktif olarak taşır. Bu, iletim için enerji kullanılmasını sağlar."},{"t":"Ksilem","a":"Ölü hücre","d":"Ksilem hücreleri ise olgunlukta ölüdür ve suyu pasif olarak (terleme çekimiyle) taşır. Bu temel fark iki dokunun çalışma biçimini ayırır."}],"ans":"Floem canlı olup besni aktif taşırken, ölü ksilem suyu pasif taşır; bu temel çalışma farkını oluşturur."},{"q":"Bir bitkide depo organlarının (yumru, kök) mevsime göre kaynak ya da havuz olabilmesi ne demektir?","steps":[{"t":"Depo dolarken","a":"Havuz","d":"Büyüme mevsiminde yapraklardan gelen şeker depo organda nişasta olarak biriktirilir; bu sırada depo organ bir havuzdur. Besin ona doğru taşınır."},{"t":"Depo boşalırken","a":"Kaynak","d":"İlkbaharda yeni sürgünler için depo organdaki nişasta şekere çevrilip floeme verilir; bu durumda depo organ kaynağa dönüşür. Besin ondan diğer organlara taşınır."}],"ans":"Depo organ, besin biriktirirken havuz, depoladığı besni dışarı verirken kaynak olur; rolü mevsime göre değişir."},{"q":"Floemin gövdedeki konumu genellikle nasıldır?","steps":[{"t":"İletim demeti","a":"Ksilemle birlikte","d":"Floem, ksilemle birlikte iletim demeti (damar) içinde bulunur. İki doku yan yana çalışır."},{"t":"Konum","a":"Dış tarafta","d":"Çoğu bitkide floem demetin dış (kabuğa yakın) tarafında, ksilem ise iç tarafında yer alır. Bu yüzden halkalı kabuk soyma floemi etkiler."}],"ans":"İletim demeti içinde, genelde ksilemin dışında (kabuğa yakın) yer alır."},{"q":"Floemde besin akışının ana itici gücü nedir?","steps":[{"t":"Mekanizma","a":"Basınç-akış","d":"Floemde besin, kaynak ile havuz arasındaki basınç (turgor) farkıyla taşınır; buna basınç-akış (kütle akışı) denir. Akışın itici gücü bu basınç farkıdır."},{"t":"Su rolü","a":"Osmozla basınç","d":"Kaynakta şeker yüklenince osmozla su girer ve basınç artar; havuzda şeker alınınca basınç düşer. Bu fark çözeltiyi ittirir."}],"ans":"Kaynak ile havuz arasındaki turgor basıncı farkı (basınç-akış mekanizması) ana itici güçtür."},{"q":"Floem ile ksilem arasındaki su geçişi neden önemlidir?","steps":[{"t":"Kaynakta su girişi","a":"Floeme su gerekir","d":"Kaynakta şeker yüklendiğinde floeme osmozla su girmesi gerekir; bu su büyük ölçüde komşu ksilemden gelir. Böylece floemde basınç oluşur."},{"t":"Havuzda su çıkışı","a":"Ksileme döner","d":"Havuzda şeker boşaltıldığında floemdeki fazla su tekrar ksileme geçebilir. Bu su alışverişi basınç-akışın sürmesini sağlar."}],"ans":"Kaynakta ksilemden floeme su girip basınç oluşturur, havuzda floemden ksileme su döner; bu alışveriş basınç-akışı sürdürür."},{"q":"Floemin yaprak damarlarındaki işlevi nedir?","steps":[{"t":"Damar yapısı","a":"Ksilem ve floem içerir","d":"Yaprak damarları iletim demetlerinin yaprak içindeki uzantısıdır; hem ksilem hem floem içerir. Floem burada besin toplama görevi görür."},{"t":"Floemin görevi","a":"Şeker toplar","d":"Yaprak hücrelerinde üretilen şeker, yaprak damarlarındaki floeme yüklenip dışarı taşınmak üzere toplanır. Buradan gövde floemine aktarılır."}],"ans":"Yaprakta üretilen şekeri floeme yükleyip toplar ve gövdeye taşınmak üzere iletir."},{"q":"Floem besni neden çift yönlü taşıyabilir, bunu kaynak-havuz ilişkisiyle açıklayınız.","steps":[{"t":"Kaynak konumu","a":"Değişken","d":"Bir bitkide kaynak (olgun yaprak) genellikle ortada ya da üstte bulunur, ama havuzlar hem altta (kök) hem üstte (genç sürgün, meyve) olabilir. Yani havuzlar farklı yönlerdedir."},{"t":"Akış yönü","a":"Havuza doğru","d":"Besin daima kaynaktan ihtiyaç duyan havuza doğru akar. Havuz altta ise besin aşağı, üstte ise yukarı taşınır."},{"t":"Sonuç","a":"Çift yön","d":"Havuzlar hem altta hem üstte olabildiğinden floemdeki net akış aynı anda farklı borularda farklı yönlerde olabilir. Bu yüzden floem iletimi çift yönlüdür."}],"ans":"Besin kaynaktan havuza akar; havuzlar hem altta hem üstte olabildiği için akış aynı anda farklı yönlerde olur, yani çift yönlüdür."},{"q":"Floem yüklenmesinde aktif taşımanın rolü nedir?","steps":[{"t":"Derişim engeli","a":"Floemde şeker yüksek","d":"Kaynaktaki floemde şeker derişimi, çevre hücrelerden daha yüksektir. Bu yüzden şeker, derişim eğimine ters yönde floeme girmek zorundadır."},{"t":"Aktif taşıma","a":"Enerji harcanır","d":"Şekerin derişim eğimine ters yönde floeme yüklenmesi ATP harcayan aktif taşıma ile yapılır. Bu işlemi arkadaş hücreler yürütür."},{"t":"Sonuç","a":"Yüksek basınç","d":"Aktif yükleme floemde yüksek şeker derişimi ve osmozla yüksek su basıncı oluşturur. Bu basınç da kütle akışını başlatır."}],"ans":"Şeker derişim eğimine ters yönde floeme aktif taşımayla (ATP ile) yüklenir; bu yüksek basınç oluşturup kütle akışını başlatır."}],"zor":[{"q":"Münch basınç-akış hipotezini aşamalı olarak açıklayınız.","steps":[{"t":"Kaynak yüklemesi","a":"Şeker ve su girer","d":"Kaynakta (olgun yaprak) şeker aktif taşımayla floeme yüklenir; artan derişim osmozla komşu ksilemden floeme su çeker. Böylece kaynak ucunda yüksek turgor basıncı oluşur."},{"t":"Basınç eğimi","a":"Kütle akışı","d":"Havuzda şeker hücrelere boşaltıldığı için derişim ve dolayısıyla basınç düşer. Kaynak ile havuz arasındaki basınç eğimi, besin çözeltisini kütle halinde havuza doğru ittirir."},{"t":"Havuz boşaltması","a":"Su geri döner","d":"Havuzda şeker floemden alınınca osmotik basınç düşer ve fazla su tekrar ksileme geçer. Bu döngü kaynak yükledikçe sürekli devam eder."}],"ans":"Kaynakta şeker yüklenip osmozla su girer ve basınç artar; havuzda şeker boşalıp basınç düşer; oluşan basınç eğimi çözeltiyi kütle halinde kaynaktan havuza ittirir, su havuzda ksileme döner."},{"q":"Floem yüklemesinde simplast ve apoplast yollarının farkını ve aktif taşımanın yerini açıklayınız.","steps":[{"t":"Simplast yol","a":"Plazmodezmlerden","d":"Simplast yolda şeker, hücreler arasındaki plazmodezm bağlantıları üzerinden hücre içi kanallarla floeme ulaşır. Bu yol bazı bitkilerde derişim eğimiyle pasif olabilir."},{"t":"Apoplast yol","a":"Hücre dışından","d":"Apoplast yolda şeker önce hücre çeperleri arasındaki boşluğa salınır, sonra arkadaş hücre/kalburlu boru zarındaki taşıyıcılarla içeri alınır. Bu alım derişim eğimine ters olduğu için aktif taşıma gerektirir."},{"t":"Aktif taşıma yeri","a":"Apoplast yükleme","d":"Apoplast yolla yüklemede şeker, ATP enerjisiyle çalışan taşıyıcılarla (genelde H+ eşlikli) floeme pompalanır. Bu, floemde yüksek derişim ve basınç oluşmasını sağlar."}],"ans":"Simplast yol plazmodezmlerden (sıklıkla pasif), apoplast yol hücre dışından zar taşıyıcılarıyla olur; apoplast yüklemede şeker ATP enerjisiyle aktif taşınır."},{"q":"Halkalı kabuk soyma (girdle) deneyi floemin işlevini nasıl kanıtlar ve sonucunu yorumlayınız.","steps":[{"t":"Deney düzeneği","a":"Floem kesilir","d":"Gövde kabuğu (floem ve kambiyum) bir kuşak halinde çıkarılır, ksilem içte sağlam bırakılır. Böylece yalnızca floem iletimi kesilmiş olur."},{"t":"Üstte birikim","a":"Şişkinlik oluşur","d":"Bir süre sonra kesiğin üst kenarında besin birikip doku kalınlaşır ve şişkinlik görülür. Bu, yapraktan gelen besnin aşağı (köke) inemediğini gösterir."},{"t":"Yorum","a":"Floem besni aşağı taşır","d":"Besnin kesik üstünde toplanması, floemin besni yapraktan köke (aşağı) taşıdığını kanıtlar. Ksilemin su iletimi sürdüğü için bitki bir süre yaşamaya devam eder, bu da floem ile ksilemin görev ayrımını gösterir."}],"ans":"Floem kesilince besin köke inemeyip kesik üstünde birikir ve şişkinlik yapar; bu, floemin besni aşağı taşıdığını ve ksilemden farklı işlev gördüğünü kanıtlar."},{"q":"Yaprak biti (afit) kullanılarak floem içeriğinin incelenmesi yöntemini ve bilimsel değerini açıklayınız.","steps":[{"t":"Afitin beslenmesi","a":"Hortumu floeme girer","d":"Yaprak bitleri ince ağız hortumlarını (stilet) doğrudan tek bir kalburlu boruya batırarak beslenir. Floemdeki yüksek basınç, besin çözeltisini afitin içine ittirir."},{"t":"Stilet kesimi","a":"Sızıntı toplanır","d":"Araştırmacılar afiti uyuşturup hortumunu keser; kesilen hortumdan floem basıncıyla sızan damlalar toplanır. Bu damlalar saf floem içeriğini temsil eder."},{"t":"Bilimsel değer","a":"İçerik ve basınç ölçümü","d":"Toplanan sızıntı analiz edilerek floemde başlıca sakkaroz taşındığı ve floemdeki basınç saptanmıştır. Bu yöntem, basınç-akış hipotezini destekleyen önemli kanıtlar sağlamıştır."}],"ans":"Afit hortumu tek kalburlu boruya girer; hortum kesilince floem basıncıyla sızan damlalar toplanır. Analizi floemde sakkaroz taşındığını ve yüksek basıncı göstererek basınç-akış hipotezini destekler."},{"q":"Bir genç sürgünün hem ksilemden su hem floemden besin alması, kaynak-havuz ilişkisi açısından ne ifade eder?","steps":[{"t":"Genç sürgün","a":"Henüz az fotosentez","d":"Genç ve gelişmekte olan sürgün yaprakları yeterince fotosentez yapamaz ve kendi besnini karşılayamaz. Bu yüzden dışarıdan besne ihtiyaç duyar."},{"t":"Havuz konumu","a":"Floemden alır","d":"Genç sürgün bir havuz olduğundan floem besni (sakkaroz) ona doğru taşır. Bu besin, olgun yapraklardaki kaynaklardan gelir."},{"t":"Su da gerekir","a":"Ksilemden alır","d":"Aynı sürgün büyümek ve turgorunu korumak için ksilemden su da alır. Yani genç sürgün hem floemin havuzu hem ksilemin su alıcısıdır; iki iletim sistemi birlikte onu besler."}],"ans":"Genç sürgün yeterli fotosentez yapamadığından floemin havuzudur ve besni floemden alır; büyümek için ksilemden de su alır, yani iki iletim sistemi birlikte onu besler."},{"q":"Floemde sakkarozun glikoz yerine taşınmasının avantajları nelerdir?","steps":[{"t":"Kimyasal kararlılık","a":"Sakkaroz az tepkin","d":"Sakkaroz indirgen olmayan bir şekerdir ve glikoza göre kimyasal olarak daha kararlıdır. Bu, taşıma sırasında istenmeyen tepkimelere girme olasılığını azaltır."},{"t":"Metabolik koruma","a":"Doğrudan kullanılmaz","d":"Sakkaroz hücre solunumunda doğrudan kullanılmadığı için taşıma sırasında hücreler tarafından kolayca tüketilmez. Böylece besin hedef havuza kayıpsız ulaşır."},{"t":"Taşıma verimi","a":"İki birim şeker","d":"Sakkaroz bir molekülünde iki şeker birimi (glikoz+fruktoz) taşıdığı için aynı molekül sayısıyla daha çok şeker iletilir. Bu, floem iletimini daha verimli kılar."}],"ans":"Sakkaroz daha kararlı, metabolizmada doğrudan tüketilmez ve tek molekülde iki şeker birimi taşır; bu özellikler taşımayı güvenli ve verimli kılar."},{"q":"Floem hücrelerinin çekirdeklerini kaybetmesine rağmen canlı kalabilmesini hangi yapı sağlar ve nasıl?","steps":[{"t":"Çekirdek kaybı","a":"Yaşamsal eksiklik","d":"Kalburlu boru elemanları olgunlukta çekirdeklerini ve birçok organellerini kaybeder. Bu durumda hücre kendi yaşamsal işlevlerini tek başına yürütemez."},{"t":"Arkadaş hücre","a":"Destek sağlar","d":"Yan yana bulunan çekirdekli arkadaş hücreler, kalburlu borunun ihtiyaç duyduğu protein ve metabolik desteği sağlar. İki hücre plazmodezmlerle yoğun biçimde bağlıdır."},{"t":"Sonuç","a":"Canlılık sürer","d":"Arkadaş hücreden gelen destek sayesinde kalburlu boru canlı kalıp besin taşımayı sürdürebilir. Bu yakın işbirliği floem iletiminin temelidir."}],"ans":"Çekirdekli arkadaş hücreler, plazmodezmlerle bağlı kalburlu boruya protein ve metabolik destek sağlayarak onun çekirdeksiz olmasına rağmen canlı kalmasını sağlar."},{"q":"Floem iletiminin çift yönlü olmasının bitki için ekolojik/fizyolojik avantajı nedir?","steps":[{"t":"Esnek dağıtım","a":"İhtiyaca göre yön","d":"Çift yönlü iletim, besnin o anda en çok ihtiyaç duyan organa (kök, meyve, sürgün) yönlendirilmesini sağlar. Yön sabit olmadığı için dağıtım esnektir."},{"t":"Mevsimsel uyum","a":"Depo kullanımı","d":"Depo organlar mevsime göre kaynak ya da havuz olabildiğinden, çift yönlü floem besni hem depolayabilir hem de gerektiğinde geri çağırabilir. Bu, mevsim değişimlerine uyumu kolaylaştırır."},{"t":"Sonuç","a":"Verimli kaynak yönetimi","d":"Bu esneklik, bitkinin sınırlı besin kaynaklarını büyüme, üreme ve depolama arasında en verimli biçimde paylaştırmasını sağlar. Bu da hayatta kalma ve üreme başarısını artırır."}],"ans":"Çift yönlülük besni o anki en kritik havuza esnek biçimde yönlendirir ve depo organların mevsimsel kullanımı sağlar; bu da sınırlı kaynakların verimli yönetilmesini ve uyumu artırır."},{"q":"Floemdeki basıncın çok yüksek olması neden gerekir ve bu basınç nasıl korunur?","steps":[{"t":"Akış için basınç","a":"İtici güç","d":"Kütle akışında besin çözeltisinin kaynaktan havuza akabilmesi için kaynakta yüksek turgor basıncı bulunmalıdır. Basınç ne kadar yüksekse akış o kadar güçlü olur."},{"t":"Basıncın oluşumu","a":"Şeker yükleme + osmoz","d":"Kaynakta şekerin aktif yüklenmesi floemde derişimi artırır ve osmozla ksilemden su çeker; bu da basıncı yükseltir. Sürekli yükleme basıncı korur."},{"t":"Çeper desteği","a":"Çökme önlenir","d":"Floem hücrelerinin çeperleri bu yüksek iç basınca dayanacak şekilde sağlamdır ve kalburlu levhalar akışı yönlendirir. Böylece yüksek basınç korunur ve hücre patlamaz."}],"ans":"Yüksek basınç kütle akışının itici gücüdür; sürekli aktif şeker yükleme ve osmozla su girişi basıncı oluşturup korur, sağlam çeperler de bu basınca dayanır."},{"q":"Kalloz birikimi floemde hangi durumda gerçekleşir ve işlevi nedir?","steps":[{"t":"Hasar durumu","a":"Boru zarar görür","d":"Floem yaralandığında ya da zarar gördüğünde kalburlu levhalardaki gözeneklerde kalloz adlı bir karbonhidrat hızla birikir. Bu, hasarlı boruya bir tepki olarak gelişir."},{"t":"Gözenek tıkama","a":"Sızıntı durur","d":"Biriken kalloz kalburlu levha gözeneklerini tıkayarak besin çözeltisinin dışarı sızmasını engeller. Böylece değerli besin kaybı önlenir."},{"t":"İşlev","a":"Koruma mekanizması","d":"Kalloz tıkacı, hasarlı bölgeyi yalıtarak floemin geri kalanını korur ve zararlıların yayılmasını sınırlar. İyileşince kalloz çözülüp akış yeniden sağlanabilir."}],"ans":"Floem yaralandığında kalburlu levha gözeneklerinde kalloz birikir; bu gözenekleri tıkayarak besin sızıntısını ve zararı önleyen bir koruma mekanizmasıdır."},{"q":"Bir bitkide afit (yaprak biti) istilasının floem üzerinden bitkiyi nasıl zayıflattığını açıklayınız.","steps":[{"t":"Floemden emme","a":"Besin çekilir","d":"Afitler hortumlarını kalburlu borulara batırıp floemdeki yüksek basınçlı besin çözeltisini sürekli emer. Böylece bitkinin ürettiği besin doğrudan çalınmış olur."},{"t":"Besin kaybı","a":"Havuzlar aç kalır","d":"Floemden çekilen besin köke, meyveye ve genç sürgünlere yeterince ulaşamaz. Bu organlar gelişimini yavaşlatır ve bitki genel olarak zayıflar."},{"t":"Ek zarar","a":"Hastalık taşır","d":"Afitler floemden beslenirken bitkiye virüs gibi hastalık etkenlerini de bulaştırabilir. Böylece besin kaybına ek olarak hastalık da bitkiyi daha çok zayıflatır."}],"ans":"Afitler floemden besin çözeltisini sürekli emerek havuz organları aç bırakır ve gelişimi yavaşlatır; ayrıca floem yoluyla hastalık etkenleri taşıyarak bitkiyi daha da zayıflatır."},{"q":"Floem ile ksilemin işbirliği olmadan basınç-akış mekanizmasının çalışamayacağını açıklayınız.","steps":[{"t":"Su kaynağı","a":"Ksilemden gelir","d":"Kaynakta şeker yüklendiğinde floeme osmozla girecek suyun büyük bölümü komşu ksilemden sağlanır. Ksilem olmadan bu su temin edilemez."},{"t":"Basınç oluşumu","a":"Su girince artar","d":"Ksilemden floeme giren su, kaynak ucunda turgor basıncını yükseltir ve kütle akışını başlatır. Yani basıncın oluşması ksilem suyuna bağlıdır."},{"t":"Su geri dönüşü","a":"Havuzda ksileme","d":"Havuzda şeker boşaltılınca floemdeki fazla su tekrar ksileme geçerek döngü tamamlanır. Bu su alışverişi olmadan basınç farkı sürdürülemez ve akış durur."}],"ans":"Basınç-akış için gereken su kaynakta ksilemden floeme girip basınç oluşturur, havuzda floemden ksileme döner; bu su alışverişi olmadan basınç farkı korunamaz ve mekanizma çalışamaz."},{"q":"İletim demetlerinde floemin dışta, ksilemin içte konumlanmasının kambiyum etkinliğiyle ilişkisini açıklayınız.","steps":[{"t":"Kambiyum konumu","a":"İki doku arasında","d":"Vasküler kambiyum, iletim demetinde ksilem ile floem arasında yer alan bölünür dokudur. Sürekli bölünerek yeni iletim dokusu üretir."},{"t":"Üretim yönü","a":"İçe ksilem, dışa floem","d":"Kambiyum içe doğru yeni ksilem (ikincil ksilem/odun), dışa doğru yeni floem üretir. Bu yüzden ksilem içte, floem dışta birikir."},{"t":"Sonuç","a":"Düzenli kalınlaşma","d":"Bu yönlü üretim, gövdenin her yıl düzenli biçimde enine kalınlaşmasını sağlar ve floemi kabuğa yakın tutar. Floemin dışta olması, halkalı kabuk soymanın onu kolayca kesebilmesini de açıklar."}],"ans":"Kambiyum ksilem ile floem arasında bulunup içe ksilem, dışa floem ürettiği için ksilem içte, floem dışta kalır; bu yönlü üretim gövdenin düzenli enine kalınlaşmasını sağlar."},{"q":"Floem iletim hızının ksileme göre düşük olmasının nedenlerini açıklayınız.","steps":[{"t":"Canlı hücre direnci","a":"İçerik akışı yavaşlatır","d":"Floem hücreleri canlıdır ve kalburlu levhalardaki gözeneklerle sitoplazmik içerik akışa direnç oluşturur. Bu, akışı ksileme göre yavaşlatır."},{"t":"Aktif süreç","a":"Yükleme zaman alır","d":"Floem akışı, kaynakta aktif şeker yüklemesine ve basınç oluşumuna bağlıdır; bu süreçler zaman ve enerji gerektirir. Pasif su akışından daha yavaş işler."},{"t":"Ksilem karşılaştırması","a":"Ölü, boş, hızlı","d":"Ksilem ise ölü ve içi boş borulardan oluşup terleme çekimiyle düşük dirençli, hızlı su akışı sağlar. Bu nedenle ksilem iletimi floemden belirgin biçimde hızlıdır."}],"ans":"Floem canlı hücreler ve kalburlu levha gözenekleriyle akışa direnç gösterir ve aktif yükleme gerektirir; ölü, boş borulardan oluşan ksilem ise düşük dirençli hızlı su akışı sağladığı için floem iletimi daha yavaştır."},{"q":"Bir ağaçta sonbaharda yaprakların besni geri çekip dökülmesi olayında floemin rolünü açıklayınız.","steps":[{"t":"Geri çekme","a":"Besin floeme yüklenir","d":"Sonbaharda yapraklar dökülmeden önce içlerindeki değerli besin ve bazı maddeler floeme yüklenir. Böylece bu maddeler boşa atılmaz."},{"t":"Floemle taşıma","a":"Gövde ve köke","d":"Floem, yapraktan geri çekilen besni gövdeye ve köke (depo organlara) taşır. Burada besin kış için depolanır."},{"t":"Sonuç","a":"Kaynak korunur","d":"Yaprak böylece bir kaynak gibi davranıp besni floemle havuzlara aktarır, sonra dökülür. Bu sayede ağaç değerli besni kaybetmeden kışa hazırlanır ve ilkbaharda kullanabilir."}],"ans":"Yaprak dökülmeden önce besni floeme yükler; floem bu besni gövde ve köke taşıyıp depolatır, böylece ağaç değerli besni kaybetmeden kışa hazırlanır."}]}},"kokDikot":{"ilkokul":{"kolay":[{"q":"Çift çenekli bir bitkinin kökünü topraktan çekersek elimizde kalan en dış, ince koruyucu tabaka hangisidir?","steps":[{"t":"Kökün dış yüzeyi","a":"En dışta tek sıra hücre vardır.","d":"Kökün toprakla temas eden en dış yüzeyini ince bir hücre tabakası kaplar. Bu tabaka kökün içini korur ve dış ortamla sınırı oluşturur."},{"t":"Tabakanın adı","a":"Bu tabakaya epidermis denir.","d":"En dıştaki bu koruyucu tek sıra hücre tabakasına epidermis adı verilir. Epidermis hem korur hem de su almaya yardımcı olur."}],"ans":"Epidermis (kökün en dış koruyucu tabakası)"},{"q":"Çift çenekli bitki kökünün yüzeyinde görülen ince tüy benzeri uzantıların temel görevi nedir?","steps":[{"t":"Tüylerin yeri","a":"Kökün dış yüzeyinde küçük tüyler bulunur.","d":"Kökün toprağa değen kısmında çok sayıda ince tüy bulunur. Bu tüyler kökün toprakla temas yüzeyini artırır."},{"t":"Görevleri","a":"Tüyler su ve mineral emer.","d":"Bu emici tüyler topraktan su ve mineralleri içeri çeker. Yüzeyi büyüttükleri için bitki daha çok su alabilir."}],"ans":"Topraktan su ve mineral emmek (emici tüyler)"},{"q":"Bir bitkinin toprağa sağlam tutunmasını sağlayan organ hangisidir?","steps":[{"t":"Bitkinin kısımları","a":"Bitkide kök, gövde, yaprak bulunur.","d":"Bitkinin toprak altında kalan kısmı vardır, toprak üstünde kalan kısımları da vardır. Toprak altındaki kısım bitkiyi yere bağlar."},{"t":"Tutunmayı sağlayan kısım","a":"Kök bitkiyi tutturur.","d":"Kök, toprağın içine doğru uzayarak bitkiyi yere sabitler. Böylece rüzgar veya yağmurda bitki devrilmez."}],"ans":"Kök"},{"q":"Çift çenekli bir bitki kökünün ortasında, suyu yukarı taşıyan borular bulunur. Bu suyun gittiği yön neresidir?","steps":[{"t":"Suyun girişi","a":"Su kökün dışından içeri girer.","d":"Su önce topraktan emici tüylerle alınır. Sonra kökün içine doğru ilerler."},{"t":"Suyun yönü","a":"Su kökten gövdeye doğru çıkar.","d":"Kökün ortasındaki borular suyu yukarıya, gövde ve yapraklara taşır. Böylece bitkinin her yerine su ulaşır."}],"ans":"Yukarıya, gövde ve yapraklara doğru"},{"q":"Bazı çift çenekli bitkiler (örneğin havuç) köklerinde besin depolar. Bu durumun bitkiye faydası nedir?","steps":[{"t":"Kökte depo","a":"Kök besin depolayabilir.","d":"Bazı bitkilerin kökleri kalınlaşarak içinde besin biriktirir. Havuç ve turp bunlara örnektir."},{"t":"Faydası","a":"Bitki bu besini ihtiyaç halinde kullanır.","d":"Depolanan besin, bitkinin zor zamanlarda veya büyürken kullanması içindir. Böylece bitki yedek enerjiye sahip olur."}],"ans":"Bitkiye yedek besin sağlamak (besin deposu)"}],"zor":[{"q":"Çift çenekli bir bitki kökünü dıştan içe doğru incelediğimizde su emmeden suyu taşımaya kadar olan sıralamayı düşünelim. Su, emildikten sonra önce nereden geçer?","steps":[{"t":"Suyun başlangıcı","a":"Su emici tüylerle alınır.","d":"En dıştaki tüyler topraktan suyu emer. Bu su kökün iç tabakalarına doğru ilerlemeye başlar."},{"t":"İlk geçilen bölge","a":"Su dıştan iç tabakalara geçer.","d":"Emilen su, dış tabakanın hemen altındaki gevşek hücre bölgesine geçer. Buradan kökün ortasına doğru yol alır."},{"t":"Sonuç","a":"Su en sonunda ortadaki borulara ulaşır.","d":"Su, kökün ortasındaki taşıma borularına varır. Oradan yukarıya, gövdeye doğru taşınır."}],"ans":"Dış tüylerden iç hücre tabakalarına, oradan ortadaki taşıma borularına"},{"q":"Çift çenekli bir bitki kökünde emici tüyler neden uzun ve ince yapıdadır? Bunun su almaya etkisi nedir?","steps":[{"t":"Tüylerin şekli","a":"Tüyler ince ve uzundur.","d":"Emici tüyler tek tek ince uzun uzantılar halindedir. Bu sayede toprak taneleri arasına kolayca girerler."},{"t":"Yüzey etkisi","a":"İnce uzun olunca yüzey artar.","d":"İnce ve uzun olmaları toprakla temas eden yüzeyi büyütür. Yüzey ne kadar büyükse o kadar çok su emilir."},{"t":"Sonuç","a":"Daha çok su alınır.","d":"Geniş yüzey sayesinde bitki topraktan daha fazla su ve mineral çekebilir. Bu da bitkinin sağlıklı büyümesini sağlar."}],"ans":"İnce uzun olmaları temas yüzeyini artırır, böylece daha çok su emilir"},{"q":"Havuç gibi besin depolayan bir kök ile sadece tutunma görevi yapan ince bir kök arasında ne gibi bir fark vardır?","steps":[{"t":"İnce kök","a":"İnce kök tutunma ve emme yapar.","d":"Bazı kökler ince ve dallıdır. Bunlar bitkiyi toprağa bağlar ve su emer."},{"t":"Depo kökü","a":"Depo kökü kalınlaşmıştır.","d":"Havuç gibi kökler kalınlaşarak besin biriktirir. Bu yüzden şişkin ve etli görünürler."},{"t":"Karşılaştırma","a":"Görevleri kısmen farklıdır.","d":"Her ikisi de tutunma sağlar, ancak depo kökü ek olarak besin saklar. İnce kökün ana işi su emmek ve tutturmaktır."}],"ans":"Depo kökü kalınlaşıp besin saklar; ince kök esas olarak tutunur ve su emer"},{"q":"Bir çift çenekli bitkinin kökü kesilirse veya zarar görürse bitkinin yaprakları neden zamanla solar?","steps":[{"t":"Kökün görevi","a":"Kök su ve mineral emer.","d":"Kök topraktan suyu alıp gövdeye gönderir. Yapraklar bu suya ihtiyaç duyar."},{"t":"Zarar durumu","a":"Kök zarar görünce su alımı azalır.","d":"Kök kesilirse veya bozulursa topraktan su emilmesi düşer. Böylece yukarıya yeterince su gidemez."},{"t":"Sonuç","a":"Yapraklar susuz kalır.","d":"Su alamayan yapraklar gerginliğini kaybeder ve solar. Bu nedenle sağlıklı kök bitki için çok önemlidir."}],"ans":"Kök su ememez, yapraklar susuz kalıp solar"},{"q":"Çift çenekli bir bitki kökünde su emildikten sonra suyun ortadaki borulara ulaşması, en dış tabakanın korumasıyla nasıl ilişkilidir?","steps":[{"t":"Dış koruma","a":"En dışta epidermis korur.","d":"Kökün en dışındaki tabaka epidermis kökün içini korur. Aynı zamanda emici tüyler bu tabakadandır."},{"t":"Suyun yolu","a":"Su içeri doğru ilerler.","d":"Emilen su koruyucu tabakadan geçerek iç bölgelere ilerler. Bu yol boyunca su kontrollü bir şekilde taşınır."},{"t":"Borulara ulaşım","a":"Su ortadaki borulara varır.","d":"Su sonunda kökün ortasındaki taşıma borularına ulaşır. Bu borular suyu güvenle yukarıya iletir."}],"ans":"Epidermis koruyup tüylerle su alır, su içe ilerleyip ortadaki taşıma borularına ulaşır"}]},"ortaokul":{"kolay":[{"q":"Dikot (çift çenekli) bitki kökünün enine kesitinde en dıştan içe doğru ilk üç tabaka nasıl sıralanır?","steps":[{"t":"En dış tabaka","a":"En dışta epidermis vardır.","d":"Kökün dışını tek sıra epidermis hücreleri kaplar. Bu tabaka emici tüyleri de taşır."},{"t":"Orta tabaka","a":"Altında korteks bulunur.","d":"Epidermisin altında geniş bir korteks bölgesi yer alır. Korteks gevşek hücrelerden oluşur ve madde geçişine izin verir."},{"t":"İç sınır","a":"Korteksin içinde endodermis vardır.","d":"Korteksin en içinde tek sıra endodermis hücreleri bulunur. Endodermis suyun geçişini denetler."}],"ans":"Epidermis, korteks, endodermis"},{"q":"Dikot kökünde endodermis hücrelerinin çeperinde bulunan ve suyun rastgele geçişini engelleyen yapı hangisidir?","steps":[{"t":"Endodermisin yeri","a":"Endodermis korteks ile merkez arasındadır.","d":"Endodermis, kökün iç silindirini saran tek sıra hücredir. Buraya gelen su denetimli olarak geçer."},{"t":"Özel kuşak","a":"Hücre çeperinde su geçirmez bir kuşak vardır.","d":"Endodermis hücrelerinin yan çeperlerinde su geçirmeyen bir şerit bulunur. Buna Kaspari şeridi denir."}],"ans":"Kaspari şeridi"},{"q":"Dikot kökte iletim demetleri ksilem ve floem olarak nasıl dizilmiştir?","steps":[{"t":"İletim dokuları","a":"Ksilem ve floem iletimi sağlar.","d":"Ksilem su ve mineral taşır, floem ise besin taşır. İkisi de kökün merkez kısmında yer alır."},{"t":"Diziliş","a":"Sıralı (radyal) dizilirler.","d":"Dikot kökte ksilem merkezde yıldız/çarpı şeklindedir, floem ise ksilem kollarının aralarında yer alır. Buna radyal diziliş denir."}],"ans":"Radyal diziliş: ksilem merkezde çarpı/yıldız şeklinde, floem kollar arasında"},{"q":"Dikot kökte ksilemin enine kesitte görünen şekli nasıldır?","steps":[{"t":"Ksilemin yeri","a":"Ksilem merkezdedir.","d":"Su taşıyan ksilem dikot kökün tam ortasında bulunur. Buradan dışa doğru kollar uzanır."},{"t":"Şekli","a":"Yıldız veya çarpı gibi görünür.","d":"Ksilem merkezden dışa doğru kollar verir ve enine kesitte yıldız ya da çarpı şekli oluşturur. Floem bu kolların arasına yerleşir."}],"ans":"Yıldız/çarpı şeklinde (merkezden kollar uzanan)"},{"q":"Dikot kökünde öz (medulla) bölgesi neden çok küçük veya gözle görülmeyecek kadar azdır?","steps":[{"t":"Merkezin durumu","a":"Merkezi ksilem doldurur.","d":"Dikot kökte ksilem tam merkeze yerleşmiş ve yıldız şeklinde yayılmıştır. Bu yapı merkezi büyük ölçüde kaplar."},{"t":"Öz bölgesi","a":"Öze az yer kalır.","d":"Ksilem merkezi doldurduğu için öz bölgesine çok az yer kalır. Bu yüzden dikot kökte öz küçük ya da yoktur."}],"ans":"Ksilem merkezi doldurduğu için öze yer kalmaz (öz küçük/yok)"}],"zor":[{"q":"Dikot kökte topraktan emilen suyun endodermisten geçerken neden kontrol edildiğini Kaspari şeridi üzerinden açıklayınız.","steps":[{"t":"Suyun yolu","a":"Su korteksten endodermise gelir.","d":"Topraktan emilen su korteksin gevşek hücreleri arasından ilerler. Bu yola hücre çeperleri arasından giden apoplast yolu denir."},{"t":"Engel","a":"Kaspari şeridi çeper yolunu kapatır.","d":"Endodermiste yan çeperlerdeki Kaspari şeridi su geçirmez yapıdadır. Bu nedenle su artık çeperden ilerleyemez."},{"t":"Sonuç","a":"Su hücre içinden geçmek zorunda kalır.","d":"Su, mecburen endodermis hücresinin içinden (zarından) geçer. Böylece bitki hangi maddenin gireceğini denetleyebilir."}],"ans":"Kaspari şeridi çeper yolunu kapatır, su hücre zarından geçmek zorunda kalır ve denetlenir"},{"q":"Dikot kökte perisikl tabakasının yeri ve önemi nedir?","steps":[{"t":"Perisiklin yeri","a":"Endodermisin hemen içinde yer alır.","d":"Perisikl, endodermisin iç tarafında bulunan ince bir hücre tabakasıdır. İletim demetlerini çevreler."},{"t":"Önemi","a":"Yan kök oluşumunu başlatır.","d":"Perisikl hücreleri bölünme yeteneğine sahiptir. Bu hücreler bölünerek yeni yan kökler oluşturur."},{"t":"Ek rol","a":"İkincil büyümeye katkı sağlar.","d":"Perisikl, ilerleyen dönemde kökün kalınlaşmasına da katkıda bulunur. Bu yüzden dikot kökte önemlidir."}],"ans":"Endodermisin iç yanında bulunur; yan kök oluşumunu ve kalınlaşmayı sağlar"},{"q":"Dikot kökünün ileride kalınlaşabilmesi (ikincil büyüme) hangi temel özelliğiyle ilgilidir?","steps":[{"t":"Kalınlaşma kavramı","a":"Kök çapı zamanla artar.","d":"Bazı bitkilerin kökleri yaşlandıkça kalınlaşır. Buna ikincil büyüme denir."},{"t":"Gerekli yapı","a":"Bölünebilen doku gerekir.","d":"Kalınlaşma için sürekli bölünen meristem hücreleri gerekir. Dikot kökte ksilem ile floem arasında bu tür bir bölünme tabakası oluşur."},{"t":"Sonuç","a":"Dikot kök kalınlaşabilir.","d":"Bu bölünme tabakası sayesinde dikot kök çapça büyür. Bu nedenle ağaç gibi dikotların kökleri kalın olabilir."}],"ans":"Ksilem ile floem arasında bölünebilen meristem (kambiyum) bulunması"},{"q":"Dikot kökte ksilem ve floemin radyal (sıralı) dizilişi, suyun ve besinin taşınmasını nasıl etkiler?","steps":[{"t":"Ksilemin yeri","a":"Ksilem merkezde yıldız şeklinde.","d":"Ksilem merkezde olduğu için her yönden gelen su kolayca toplanır. Su buradan yukarıya taşınır."},{"t":"Floemin yeri","a":"Floem ksilem kolları arasında.","d":"Floem, ksilem kollarının arasına yerleşmiştir. Bu konum besinin köke ulaşmasını ve dağılmasını kolaylaştırır."},{"t":"Sonuç","a":"İletim verimli olur.","d":"Bu radyal diziliş su ve besin yollarını birbirinden ayrı ama yakın tutar. Böylece iletim düzenli ve verimli gerçekleşir."}],"ans":"Merkezdeki ksilem suyu toplayıp yukarı taşır, aralarındaki floem besini dağıtır; iletim verimli olur"},{"q":"Bir kök kesitinde \"öz bölgesinin çok küçük olması\" ve \"ksilemin merkezde yıldız şeklinde olması\" gözleniyorsa bu kökün dikot mu monokot mu olduğunu nasıl anlarız?","steps":[{"t":"Gözlenen özellikler","a":"Küçük öz, merkezde yıldız ksilem.","d":"Kesitte öz bölgesi neredeyse yok denecek kadar küçüktür. Ksilem ise merkezde yıldız/çarpı şeklinde durmaktadır."},{"t":"Karşılaştırma","a":"Monokotta öz geniştir.","d":"Monokot kökte öz geniştir ve ksilem-floem demetleri halka şeklinde dizilir. Burada böyle bir durum yoktur."},{"t":"Sonuç","a":"Bu bir dikot köktür.","d":"Küçük öz ve merkezde yıldız şeklinde ksilem dikot kökün belirgin özelliğidir. Bu yüzden incelenen kök dikottur."}],"ans":"Dikot kök (küçük öz + merkezde yıldız şeklinde ksilem dikota özgüdür)"}]},"lise":{"kolay":[{"q":"Dikot kök enine kesitinde en dıştan merkeze doğru ana doku ve bölgelerin sırasını yazınız.","steps":[{"t":"Dış bölge","a":"Epidermis ve emici tüyler.","d":"En dışta tek sıra epidermis ve onun uzantısı olan emici tüyler bulunur. Bu bölge su ve mineral emer."},{"t":"Korteks ve sınır","a":"Korteks ve endodermis gelir.","d":"Epidermisin altında geniş korteks, onun da en içinde Kaspari şeritli endodermis yer alır. Endodermis su geçişini denetler."},{"t":"Merkezi silindir","a":"Perisikl, iletim demetleri, öz.","d":"Endodermisin içinde perisikl, sonra radyal dizilmiş ksilem-floem ve çok küçük öz bulunur. Bu bölgeye merkezi silindir denir."}],"ans":"Epidermis (+emici tüy) → korteks → endodermis → perisikl → ksilem/floem (radyal) → küçük öz"},{"q":"Dikot kökte epidermisin görevlerini ve emici tüylerin epidermisle ilişkisini açıklayınız.","steps":[{"t":"Epidermisin yapısı","a":"Tek sıra, kütikülasız hücreler.","d":"Kök epidermisi tek sıra hücreden oluşur ve kalın kütikül taşımaz. Bu sayede su geçişine izin verir."},{"t":"Emici tüyler","a":"Epidermis hücrelerinin uzantısıdır.","d":"Emici tüyler ayrı hücreler değil, epidermis hücrelerinin tek hücreli uzantılarıdır. Toprakla temas yüzeyini büyütürler."},{"t":"Görev","a":"Koruma ve emme.","d":"Epidermis hem kökü korur hem de emici tüyler aracılığıyla su ve mineral emer. Bu nedenle kök yüzeyi için kritiktir."}],"ans":"Epidermis koruma ve su emme sağlar; emici tüyler epidermis hücrelerinin yüzey artıran uzantılarıdır"},{"q":"Dikot kökte korteks bölgesinin yapısını ve işlevlerini belirtiniz.","steps":[{"t":"Yapısı","a":"Gevşek parankima hücreleri.","d":"Korteks, hücreler arası boşlukları bol olan parankima dokusundan oluşur. Bu gevşek yapı madde geçişini kolaylaştırır."},{"t":"İşlevleri","a":"İletim ve depo.","d":"Korteks emilen suyun endodermise iletilmesinde rol oynar ve nişasta gibi besinleri depolayabilir. Ayrıca gaz alışverişine de boşlukları ile katkı sağlar."}],"ans":"Gevşek parankimadan oluşur; su iletimi, besin depolama ve gaz değişimini sağlar"},{"q":"Dikot kökte endodermisin yapısı ve Kaspari şeridinin işlevi nedir?","steps":[{"t":"Endodermis","a":"Korteksin en iç sırası.","d":"Endodermis, korteks ile merkezi silindir arasında tek sıra hücre tabakasıdır. Suyun geçişini denetleyen sınırdır."},{"t":"Kaspari şeridi","a":"Su geçirmez süberinli kuşak.","d":"Endodermis hücrelerinin radyal ve enine çeperlerinde süberin/lignin içeren Kaspari şeridi bulunur. Bu kuşak apoplast yolunu keser."},{"t":"İşlevi","a":"Denetimli su geçişi.","d":"Kaspari şeridi suyu hücre içinden (simplast) geçmeye zorlar. Böylece bitki giren maddeleri seçici olarak denetler."}],"ans":"Endodermis tek sıra denetleyici tabakadır; Kaspari şeridi apoplast yolunu kesip suyu simplasta zorlar"},{"q":"Dikot kökte perisiklin yeri ve iki temel görevi nedir?","steps":[{"t":"Yeri","a":"Endodermisin hemen içinde.","d":"Perisikl, endodermisin iç tarafında merkezi silindiri saran ince tabakadır. Bölünme yeteneği olan hücrelerden oluşur."},{"t":"Görev 1","a":"Yan kök oluşturur.","d":"Perisikl hücreleri bölünerek yan (lateral) köklerin başlangıcını oluşturur. Bu yüzden yan kökler perisiklten köken alır."},{"t":"Görev 2","a":"İkincil büyümeye katılır.","d":"Perisikl ileride kambiyumla birlikte kalınlaşmaya katkı sağlar. Mantar kambiyumunun bir kısmını da oluşturabilir."}],"ans":"Endodermisin içinde yer alır; yan kök oluşturur ve ikincil büyümeye katkı sağlar"},{"q":"Dikot kökte ksilemin enine kesitteki konumu ve şekli nasıldır, görevi nedir?","steps":[{"t":"Konumu","a":"Merkezde yer alır.","d":"Dikot kökte ksilem merkezi silindirin tam ortasında bulunur. Buradan dışa doğru kollar uzanır."},{"t":"Şekli","a":"Yıldız/çarpı şeklinde.","d":"Ksilem merkezden dışa kollar vererek enine kesitte yıldız ya da çarpı görünümü oluşturur. Kol sayısı bitkiye göre değişir."},{"t":"Görevi","a":"Su ve mineral taşır.","d":"Ksilem topraktan emilen su ve mineralleri yukarıya gövdeye taşır. Bu taşıma tek yönlü ve yukarıya doğrudur."}],"ans":"Merkezde yıldız/çarpı şeklinde bulunur; su ve mineralleri yukarı taşır"},{"q":"Dikot kökte floemin konumu nasıldır ve hangi maddeyi taşır?","steps":[{"t":"Konumu","a":"Ksilem kolları arasında.","d":"Floem, merkezdeki ksilemin kolları arasındaki boşluklara yerleşir. Yani ksilem ile dönüşümlü (radyal) dizilir."},{"t":"Görevi","a":"Organik besin taşır.","d":"Floem, yapraklarda üretilen organik besinleri köke ve diğer organlara taşır. Bu taşıma iki yönlü olabilir."}],"ans":"Ksilem kollarının arasında bulunur; yapraklarda üretilen organik besini taşır"},{"q":"Dikot kök ile monokot kök arasında öz (medulla) bölgesi bakımından fark nedir?","steps":[{"t":"Dikot öz","a":"Öz çok küçük veya yok.","d":"Dikot kökte merkezi ksilem doldurduğundan öz bölgesi çok küçüktür ya da hiç yoktur. Merkez büyük ölçüde ksilemle kaplıdır."},{"t":"Monokot öz","a":"Öz geniş ve belirgin.","d":"Monokot kökte merkezde geniş bir öz (medulla) bulunur. İletim demetleri bu özün çevresinde halka yapar."}],"ans":"Dikotta öz küçük/yok, monokotta geniş ve belirgindir"},{"q":"Dikot kökte iletim demetlerinin \"radyal\" dizilişi ne anlama gelir?","steps":[{"t":"Radyal kavramı","a":"Ksilem ve floem dönüşümlü dizilir.","d":"Radyal diziliş, ksilem ve floemin aynı demet içinde üst üste değil, ayrı ayrı ve dönüşümlü (sıralı) yerleşmesidir. Yarıçap boyunca sıra ile bulunurlar."},{"t":"Kökteki görünüm","a":"Ksilem kolları, aralarda floem.","d":"Dikot kökte ksilem merkezden kollar verir, floem bu kolların arasına gelir. Böylece kesitte ksilem ve floem nöbetleşe görülür."}],"ans":"Ksilem ve floemin ayrı ayrı, yarıçap boyunca nöbetleşe (sıralı) dizilmesidir"},{"q":"Dikot kökün ikincil büyüme (kalınlaşma) yapabilmesi neden mümkündür?","steps":[{"t":"Kambiyum oluşumu","a":"Ksilem-floem arasında kambiyum oluşur.","d":"Dikot kökte ksilem ile floem arasındaki parankima hücreleri bölünme yeteneği kazanarak demet kambiyumu oluşturur. Bu sürekli bölünen meristematik dokudur."},{"t":"Sonuç","a":"Çap artar.","d":"Kambiyum içe ikincil ksilem, dışa ikincil floem üreterek kökü kalınlaştırır. Bu nedenle dikot kökler ikincil büyüme yapabilir."}],"ans":"Ksilem ile floem arasında kambiyum (yanal meristem) oluştuğu için kalınlaşabilir"},{"q":"Dikot kökte suyun apoplast ve simplast yollarıyla taşınması arasındaki fark nedir?","steps":[{"t":"Apoplast","a":"Hücre dışı yol.","d":"Apoplast yolu, suyun hücre çeperleri ve hücreler arası boşluklardan ilerlemesidir. Bu yolda su hücre içine girmeden hareket eder."},{"t":"Simplast","a":"Hücre içi yol.","d":"Simplast yolu, suyun hücre sitoplazmaları arasında plazmodesmalar yoluyla ilerlemesidir. Bu yolda su hücreden hücreye geçer."},{"t":"Endodermisteki durum","a":"Apoplast endodermiste durur.","d":"Kaspari şeridi apoplast yolunu kestiği için su endodermiste simplasta geçmek zorunda kalır. Böylece denetim sağlanır."}],"ans":"Apoplast hücre dışından, simplast hücre içinden ilerler; endodermiste apoplast kesilir"},{"q":"Dikot kökte emici tüy bölgesinin (olgunlaşma bölgesi) önemi nedir?","steps":[{"t":"Bölgenin yeri","a":"Kök ucunun biraz gerisinde.","d":"Emici tüyler, kök ucundaki uzama bölgesinin hemen gerisindeki olgunlaşma bölgesinde bulunur. Bu bölgede hücreler farklılaşmıştır."},{"t":"Önemi","a":"Asıl su emilimi burada olur.","d":"Topraktan su ve mineral emiliminin büyük kısmı bu emici tüy bölgesinde gerçekleşir. Tüyler yüzeyi artırarak emilimi en üst düzeye çıkarır."}],"ans":"Olgunlaşma bölgesindeki emici tüyler, asıl su ve mineral emiliminin yapıldığı yerdir"},{"q":"Dikot kökte korteksteki hücreler arası boşlukların işlevsel önemi nedir?","steps":[{"t":"Boşlukların varlığı","a":"Korteks gevşek yapılıdır.","d":"Korteks parankiması bol hücreler arası boşluk içerir. Bu boşluklar dokuyu gevşek hale getirir."},{"t":"İşlev","a":"Gaz ve su hareketi.","d":"Boşluklar hem suyun apoplast yoluyla ilerlemesini hem de hücrelerin solunum için gaz alışverişini kolaylaştırır. Sulak topraklarda oksijen iletiminde de önemlidir."}],"ans":"Su iletimini ve hücrelerin gaz alışverişini (oksijen iletimi) kolaylaştırır"},{"q":"Dikot kökte yan (lateral) köklerin hangi dokudan ve nasıl oluştuğunu açıklayınız.","steps":[{"t":"Köken doku","a":"Perisiklten oluşur.","d":"Yan kökler, merkezi silindiri saran perisikl tabakasındaki hücrelerin bölünmesiyle başlar. Bu nedenle iç dokudan köken alırlar (endojen)."},{"t":"Gelişim","a":"Dış dokuları yararak ilerler.","d":"Bölünen perisikl hücreleri yeni bir kök tepesi oluşturur ve bu yapı korteks ile epidermisi yararak dışa çıkar. Böylece yan kök toprağa doğru uzar."}],"ans":"Perisikl hücrelerinin bölünmesiyle (endojen) oluşur, korteks ve epidermisi yararak dışa çıkar"},{"q":"Dikot kökte merkezi silindir (stel) hangi yapıları kapsar?","steps":[{"t":"Sınır","a":"Endodermisin içinde kalan bölge.","d":"Merkezi silindir, endodermisin iç tarafında kalan tüm dokuları kapsar. Buna stel de denir."},{"t":"İçeriği","a":"Perisikl, iletim demetleri, öz.","d":"Merkezi silindir; perisikli, radyal dizilmiş ksilem ve floemi ve varsa küçük özü içerir. Bu bölge kökün iletim ve büyüme merkezi gibidir."}],"ans":"Perisikl, radyal ksilem-floem ve (varsa küçük) özü kapsar"}],"zor":[{"q":"Dikot kökte Kaspari şeridinin minerallerin seçici alımındaki rolünü hücresel düzeyde açıklayınız.","steps":[{"t":"Apoplast geçişi","a":"Mineraller önce çeperden ilerler.","d":"Topraktan alınan iyonlar başlangıçta apoplast yoluyla, yani hücre çeperleri arasından serbestçe ilerleyebilir. Bu yolda seçicilik yoktur."},{"t":"Kaspari engeli","a":"Süberin şeridi geçişi durdurur.","d":"Endodermiste Kaspari şeridi süberin/lignin içerdiğinden suya ve iyona geçirgen değildir. Bu, apoplast yolunu fiziksel olarak keser."},{"t":"Zar denetimi","a":"İyonlar zardan taşınır.","d":"İyonlar endodermis hücre zarındaki taşıyıcı proteinlerden geçmek zorunda kalır. Böylece bitki hangi mineralin merkezi silindire gireceğini seçici olarak denetler."},{"t":"Sonuç","a":"Seçici mineral alımı.","d":"Bu mekanizma sayesinde zararlı veya gereksiz iyonlar dışarıda tutulabilir. Kaspari şeridi mineral alımında bir kapı görevi görür."}],"ans":"Apoplast yolunu kesip iyonları zar taşıyıcılarına yönlendirir, böylece seçici mineral alımı sağlanır"},{"q":"Dikot kökte ikincil büyümenin başlangıcında demet kambiyumunun nasıl oluştuğunu ve ne ürettiğini açıklayınız.","steps":[{"t":"Kambiyum başlangıcı","a":"Ksilem-floem arası hücreler etkinleşir.","d":"Ksilem kolları ile floem arasındaki parankima hücreleri yeniden bölünme yeteneği kazanır. Bu hücreler birleşerek dalgalı bir kambiyum kuşağı oluşturur."},{"t":"Perisikl katkısı","a":"Ksilem karşısındaki perisikl katılır.","d":"Ksilem kollarının dış hizasındaki perisikl hücreleri de bölünerek kambiyum halkasını tamamlar. Böylece sürekli bir silindir kambiyum oluşur."},{"t":"Üretim","a":"İçe ksilem, dışa floem.","d":"Kambiyum içe doğru ikincil ksilem, dışa doğru ikincil floem üretir. Bu sürekli üretim kökün çapını artırır."},{"t":"Sonuç","a":"Kök kalınlaşır.","d":"İkincil dokuların birikmesiyle dikot kök giderek kalınlaşır. Odunsu dikotlarda bu süreç yıllarca devam eder."}],"ans":"Ksilem-floem arası parankima + perisikl kambiyumu oluşturur; içe ikincil ksilem, dışa ikincil floem üretip kökü kalınlaştırır"},{"q":"Dikot kökte suyun topraktan ksileme ulaşana kadar izlediği yolu, geçtiği tüm doku ve engellerle sırasıyla açıklayınız.","steps":[{"t":"Emilim","a":"Su emici tüyle alınır.","d":"Su, olgunlaşma bölgesindeki emici tüyler aracılığıyla topraktan alınır. Yüksek yüzey alanı emilimi artırır."},{"t":"Korteks geçişi","a":"Su korteksten ilerler.","d":"Su, korteksin gevşek parankima hücreleri arasından apoplast ve simplast yollarıyla iç kesime ilerler. Bu aşamada henüz seçicilik azdır."},{"t":"Endodermis","a":"Kaspari şeridi yolu değiştirir.","d":"Endodermiste Kaspari şeridi apoplast yolunu keser ve su simplasta, yani hücre içine geçmek zorunda kalır. Böylece denetim sağlanır."},{"t":"Ksileme ulaşma","a":"Su perisiklten ksileme varır.","d":"Su perisikli geçerek merkezdeki ksileme ulaşır. Ksilem suyu kohezyon-gerilim mekanizmasıyla yukarı taşır."}],"ans":"Emici tüy → korteks (apoplast/simplast) → endodermis (Kaspari ile simplasta zorlanır) → perisikl → ksilem"},{"q":"Dikot kökte protoksilem ve metaksilem kavramlarını, kökte ksilemin \"ekzark\" gelişimi ile birlikte açıklayınız.","steps":[{"t":"Protoksilem","a":"İlk oluşan, dar çaplı ksilem.","d":"Protoksilem, kökte ilk farklılaşan ksilem elemanlarıdır ve çapları dardır. Genellikle halkalı veya sarmal çeper kalınlaşması gösterir."},{"t":"Metaksilem","a":"Sonra oluşan, geniş çaplı ksilem.","d":"Metaksilem daha sonra olgunlaşır ve çapı daha geniştir. Daha fazla su iletimi sağlar."},{"t":"Ekzark diziliş","a":"Protoksilem dışta, metaksilem içte.","d":"Kökte protoksilem dış kenarda, metaksilem merkeze yakın yer alır; olgunlaşma dıştan içe doğrudur. Bu düzene ekzark gelişim denir ve köke özgüdür."}],"ans":"Protoksilem önce/dar/dışta, metaksilem sonra/geniş/içte oluşur; kökte ekzark (dıştan içe) gelişim görülür"},{"q":"Dikot kökte korteksin iç sınırındaki endodermis ile dış sınırındaki hipodermis/eksodermis arasındaki işlev farkını açıklayınız.","steps":[{"t":"Endodermis","a":"İç sınır, Kaspari şeritli.","d":"Endodermis korteksin merkeze bakan iç sınırıdır ve Kaspari şeridi taşır. Suyun merkezi silindire seçici geçişini denetler."},{"t":"Eksodermis","a":"Dış sınır, korumaya yönelik.","d":"Korteksin dışa bakan sınırındaki eksodermis (hipodermis) süberinleşerek su kaybını ve istenmeyen madde girişini sınırlar. Epidermis yıprandığında koruma görevini üstlenebilir."},{"t":"Fark","a":"Biri iç denetim, diğeri dış koruma.","d":"Endodermis içe doğru su geçişini düzenlerken eksodermis daha çok dış koruma ve su kaybını engelleme işlevi görür. İkisi de süberin içerebilir ama konum ve ağırlıklı görevleri farklıdır."}],"ans":"Endodermis (iç) Kaspari ile seçici geçişi denetler; eksodermis (dış) koruma ve su kaybını engeller"},{"q":"Dikot kökte yan kökün endojen (iç kökenli) oluşumunun, gövde dallarının ekzojen oluşumuna göre avantajı nedir?","steps":[{"t":"Endojen oluşum","a":"Yan kök perisiklten, içeriden çıkar.","d":"Yan kökler perisiklten köken alıp korteks ve epidermisi yararak dışa çıkar. Yani iç dokulardan başlar."},{"t":"İletim bağlantısı","a":"Demetlerle doğrudan bağlanır.","d":"Perisikl iletim demetlerine çok yakın olduğundan yeni yan kökün ksilem-floemi ana kökün iletim demetlerine kolayca bağlanır. Bu, su ve besin sürekliliğini sağlar."},{"t":"Avantaj","a":"Güçlü ve bütünleşik bağlantı.","d":"Endojen oluşum, yan kökün merkezi silindirle doğrudan ve sağlam bağlanmasını sağlar. Böylece toprakta gerilime dayanıklı, iletim açısından kesintisiz bir kök sistemi kurulur."}],"ans":"Perisiklten çıktığı için iletim demetlerine doğrudan bağlanır; güçlü ve kesintisiz su-besin iletimi sağlanır"},{"q":"Bir bilim insanı dikot kök kesitinde endodermis hücrelerinin geçit hücreleri (passage cells) içerdiğini gözlemliyor. Bu hücrelerin işlevi nedir?","steps":[{"t":"Geçit hücreleri","a":"Kaspari şeridi olmayan endodermis hücreleri.","d":"Bazı endodermis hücreleri tam süberinleşmez ve ince çeperli kalır. Bunlara geçit hücreleri (passage cells) denir."},{"t":"Konum","a":"Genellikle protoksilem hizasında.","d":"Geçit hücreleri çoğunlukla protoksilem kollarının karşısında yer alır. Bu konum su girişini iletim demetlerine yönlendirir."},{"t":"İşlev","a":"Suyun simplasta hızlı girişi.","d":"Geçit hücreleri, suyun ve iyonların endodermisten merkezi silindire daha kolay geçmesini sağlar. Böylece tamamen süberinleşmiş endodermiste bile su girişi devam eder."}],"ans":"Süberinleşmemiş geçit hücreleri, suyun ve iyonların endodermisten merkezi silindire geçişini kolaylaştırır"},{"q":"Dikot kökte kohezyon-gerilim (terleme-çekim) kuramına göre ksilemdeki suyun yukarı çıkışını köke kadar izleyerek açıklayınız.","steps":[{"t":"Terleme","a":"Yapraktan su buharlaşır.","d":"Yapraklardaki stomalardan su buharı kaybedilir (terleme). Bu kayıp ksilemde bir emme kuvveti (gerilim) doğurur."},{"t":"Kohezyon","a":"Su molekülleri birbirini çeker.","d":"Su molekülleri hidrojen bağlarıyla birbirine tutunur (kohezyon) ve ksilem çeperine yapışır (adezyon). Bu sayede su sütunu kopmadan yukarı çekilir."},{"t":"Kökten çekiş","a":"Gerilim köke kadar iletilir.","d":"Yukarıdaki gerilim ksilem boyunca aşağıya köke kadar iletilir. Bu, köteki ksileme yeni suyun çekilmesine yol açar."},{"t":"Emilim","a":"Topraktan su girer.","d":"Köteki düşük su potansiyeli, topraktan emici tüylere ve oradan ksileme su girişini sürdürür. Böylece kesintisiz bir su sütunu oluşur."}],"ans":"Terleme gerilimi kohezyonla iletilir, köteki ksileme su çekilir ve topraktan emilim sürer"},{"q":"Dikot kökte epidermisin su emen yapısı ile yaprak epidermisinin kalın kütiküllü yapısı arasındaki işlevsel zıtlığı açıklayınız.","steps":[{"t":"Kök epidermisi","a":"İnce, kütikülsüz, tüylü.","d":"Kök epidermisi kalın kütikül taşımaz ve emici tüyler içerir. Amaç su almayı kolaylaştırmaktır."},{"t":"Yaprak epidermisi","a":"Kalın kütiküllü, koruyucu.","d":"Yaprak epidermisi su kaybını önlemek için kalın kütikül salgılar. Amaç suyu içeride tutmaktır."},{"t":"İşlevsel zıtlık","a":"Biri su alır, diğeri su tutar.","d":"Kök epidermisi su emilimine, yaprak epidermisi su korunmasına uyum sağlamıştır. Bu zıtlık her organın bulunduğu ortama göre özelleşmesini gösterir."}],"ans":"Kök epidermisi kütikülsüz/tüylü olup su emer, yaprak epidermisi kalın kütikülle su kaybını önler"},{"q":"Dikot kökte sodyum gibi zararlı bir iyonun aşırı miktarda bulunduğu tuzlu toprakta Kaspari şeridi nasıl bir koruma sağlar, sınırlılığı nedir?","steps":[{"t":"Apoplast engeli","a":"Serbest iyon girişi kesilir.","d":"Kaspari şeridi apoplast yolunu kestiği için sodyum iyonları çeperden serbestçe merkezi silindire akamaz. İyonların zardan geçmesi gerekir."},{"t":"Seçici taşıma","a":"Zar taşıyıcıları sodyumu sınırlar.","d":"Endodermis zarındaki taşıyıcılar zararlı sodyumu büyük ölçüde dışarıda bırakabilir. Böylece merkezi silindire giren tuz miktarı azalır."},{"t":"Sınırlılık","a":"Aşırı tuz yine de geçebilir.","d":"Çok yüksek tuz derişiminde bir miktar sodyum yine de zardan içeri sızar ve su potansiyeli düşerek bitkinin su almasını zorlaştırır. Kaspari şeridi tamamen koruyamaz, sadece girişi yavaşlatır."}],"ans":"Apoplast yolunu kesip sodyumu zar taşıyıcılarına bağımlı kılar; ancak çok yüksek tuzda tam koruma sağlayamaz"},{"q":"Dikot kök kesitinde ksilem kollarının sayısının (örneğin tetrark, pentark) ne anlama geldiğini ve floemin bu kollarla ilişkisini açıklayınız.","steps":[{"t":"Kol sayısı","a":"Protoksilem nokta sayısıdır.","d":"Ksilemin merkezden dışa uzanan kollarının (protoksilem noktalarının) sayısı diark, triark, tetrark gibi adlandırılır. Bu sayı bitki türüne göre değişir."},{"t":"Floemin yeri","a":"Kolların arasına yerleşir.","d":"Floem demetleri, ksilem kollarının arasındaki boşluklara radyal olarak yerleşir. Yani ksilem kolu sayısı genellikle floem grubu sayısına denk gelir."},{"t":"Anlamı","a":"Tür ayrımında kullanılır.","d":"Kol sayısı dikot kökleri birbirinden ayırt etmede taksonomik bir özelliktir. Dikotlarda genellikle az sayıda (2-6) kol bulunurken monokotlarda çok sayıda (poliark) kol görülür."}],"ans":"Protoksilem kol sayısını belirtir (diark, tetrark...); floem kolların arasına dizilir, kol sayısı türe özgüdür"},{"q":"Dikot kökte korteksteki parankima hücrelerinde nişasta depolanması, bitkinin mevsimsel yaşamına nasıl katkı sağlar?","steps":[{"t":"Depolama","a":"Korteks nişasta biriktirir.","d":"Korteks parankima hücreleri amiloplastlarda nişasta depolayabilir. Bu, fazla üretilen organik besinin saklanmasıdır."},{"t":"Mevsimsel kullanım","a":"Zor dönemde besin çözülür.","d":"Kış veya kurak dönemde fotosentez azaldığında depolanan nişasta şekere çevrilip kullanılır. Böylece bitki büyümesini sürdürebilir."},{"t":"Yeniden büyüme","a":"İlkbaharda sürgün verir.","d":"Çok yıllık dikotlarda kökte depolanan besin, ilkbaharda yeni sürgün ve yaprakların hızlı gelişmesini sağlar. Bu, mevsimsel hayatta kalmayı destekler."}],"ans":"Kökte depolanan nişasta, zor dönemlerde enerji ve ilkbaharda hızlı yeniden büyüme için kullanılır"},{"q":"Dikot kökte ikincil büyüme sırasında oluşan mantar kambiyumu (fellojen) ve periderm tabakasının işlevini açıklayınız.","steps":[{"t":"Fellojen oluşumu","a":"Perisiklten mantar kambiyumu çıkar.","d":"İkincil büyüme ilerleyince perisikl hücreleri mantar kambiyumunu (fellojen) oluşturur. Bu yanal meristem epidermisin yerini alacak koruyucu doku üretir."},{"t":"Periderm üretimi","a":"Dışa mantar dokusu üretilir.","d":"Fellojen dışa doğru süberinli mantar hücreleri (fellem), içe doğru felloderm üretir. Bu tabakaların tümüne periderm denir."},{"t":"İşlev","a":"Su kaybı ve zararlılardan korur.","d":"Periderm, kalınlaşan kökün dış yüzeyini su kaybına ve patojenlere karşı korur. Epidermis yırtıldığında bu yeni koruyucu tabaka devreye girer."}],"ans":"Perisiklten oluşan fellojen periderm üretir; bu süberinli koruyucu tabaka kalınlaşan kökü su kaybı ve zararlılardan korur"},{"q":"Dikot kökte su potansiyeli kavramını kullanarak suyun topraktan emici tüye, oradan korteks hücrelerine doğru hareketini açıklayınız.","steps":[{"t":"Su potansiyeli","a":"Su yüksekten düşüğe gider.","d":"Su, su potansiyeli yüksek bölgeden düşük bölgeye doğru hareket eder. Bu hareket osmoz ile gerçekleşir."},{"t":"Topraktan tüye","a":"Tüy içi daha düşük potansiyellidir.","d":"Emici tüy hücresinde çözünmüş madde derişimi yüksek olduğundan su potansiyeli topraktan düşüktür. Bu yüzden su topraktan tüye girer."},{"t":"Hücreler arası","a":"Potansiyel basamaklı azalır.","d":"Emici tüyden korteks hücrelerine doğru su potansiyeli giderek azalır. Bu basamaklı düşüş suyun merkeze doğru sürekli akmasını sağlar."}],"ans":"Su, yüksek su potansiyelli topraktan giderek azalan potansiyelli tüy ve korteks hücrelerine osmozla ilerler"},{"q":"Dikot kök ile monokot kökün ikincil büyüme yeteneği bakımından farkını, dokusal nedeniyle birlikte açıklayınız.","steps":[{"t":"Dikot durumu","a":"İkincil büyüme yapar.","d":"Dikot kökte ksilem ile floem arasında demet kambiyumu oluşabilir. Bu kambiyum sayesinde kök çapça kalınlaşır."},{"t":"Monokot durumu","a":"Genellikle ikincil büyüme yok.","d":"Monokot kökte iletim demetleri arasında sürekli bir kambiyum oluşmaz. Bu nedenle çoğu monokot kök ikincil büyüme yapamaz."},{"t":"Dokusal neden","a":"Kambiyum varlığı belirleyicidir.","d":"İkincil büyümenin temel koşulu yanal meristem (kambiyum) bulunmasıdır. Dikotta bu doku oluştuğu için kalınlaşma olur, monokotta oluşmadığı için kök ince kalır."}],"ans":"Dikotta ksilem-floem arası kambiyum oluştuğu için ikincil büyüme olur; monokotta kambiyum oluşmadığından kök kalınlaşmaz"}]}},"kokMonokot":{"ilkokul":{"kolay":[{"q":"Tek çenekli bir bitkinin (örneğin mısır veya buğday) kökünün topraktaki temel görevlerinden biri nedir?","steps":[{"t":"Kökün yeri","a":"Kök toprak altındadır.","d":"Tek çenekli bitkilerin kökleri toprağın içine doğru yayılır. Bu kökler bitkiyi yere bağlar."},{"t":"Görevi","a":"Tutturma ve su emme.","d":"Kök hem bitkiyi toprağa sabitler hem de topraktan su ve mineral emer. Böylece bitki ayakta durur ve beslenir."}],"ans":"Bitkiyi toprağa tutturmak ve su-mineral emmek"},{"q":"Tek çenekli bitki kökünün ortasında, dikot kökten farklı olarak belirgin bir boş gibi görünen geniş bölge bulunur. Bu bölgeye ne ad verilir?","steps":[{"t":"Kesite bakış","a":"Kökün ortasında geniş bir alan var.","d":"Tek çenekli kökün enine kesitine bakıldığında tam ortada geniş bir bölge görülür. Bu bölge dolgun hücrelerden oluşur."},{"t":"Adı","a":"Bu bölgeye öz denir.","d":"Kökün ortasındaki bu geniş bölgeye öz (medulla) adı verilir. Tek çenekli kökte öz belirgin ve geniştir."}],"ans":"Öz (medulla)"},{"q":"Tek çenekli bitki kökünde de en dışta koruyucu bir tabaka vardır. Bu tabakanın adı nedir?","steps":[{"t":"Dış yüzey","a":"En dışta ince bir tabaka var.","d":"Tek çenekli kökün en dışını tek sıra hücre kaplar. Bu tabaka kökün içini korur."},{"t":"Adı","a":"Bu tabaka epidermistir.","d":"En dıştaki koruyucu tek sıra hücre tabakasına epidermis denir. Epidermis hem korur hem su almaya yardım eder."}],"ans":"Epidermis"},{"q":"Mısır gibi tek çenekli bir bitkinin kökleri genellikle saçak şeklinde, çok sayıda ince koldan oluşur. Bu yapının bitkiye faydası nedir?","steps":[{"t":"Kök şekli","a":"Çok sayıda ince kök vardır.","d":"Tek çenekli bitkilerde tek kalın bir kök yerine çok sayıda ince kök bulunur. Buna saçak kök denir."},{"t":"Faydası","a":"Toprağı daha çok sarar.","d":"Çok sayıda ince kök toprağın geniş bir alanını sarar. Böylece bitki daha sağlam tutunur ve daha çok su emer."}],"ans":"Toprağı geniş alanda sararak sağlam tutunma ve bol su emme sağlar"},{"q":"Tek çenekli bir bitki kökünün yüzeyinde de ince tüyler bulunur. Bu tüylerin görevi nedir?","steps":[{"t":"Tüylerin yeri","a":"Kök yüzeyinde tüyler var.","d":"Tek çenekli kökün dış yüzeyinde de ince emici tüyler bulunur. Bunlar toprakla temas eder."},{"t":"Görevi","a":"Su ve mineral emer.","d":"Bu tüyler topraktan su ve mineral çeker. Yüzeyi artırdıkları için emilim kolaylaşır."}],"ans":"Topraktan su ve mineral emmek"}],"zor":[{"q":"Bir tek çenekli kök ile çift çenekli kökü ortadaki öz bölgesine bakarak nasıl ayırt edebiliriz?","steps":[{"t":"Tek çenekli öz","a":"Ortada geniş öz var.","d":"Tek çenekli kökün tam ortasında geniş bir öz bölgesi bulunur. Bu bölge belirgin ve büyüktür."},{"t":"Çift çenekli öz","a":"Ortada öz küçük veya yok.","d":"Çift çenekli kökte ortada öz çok küçüktür veya hiç bulunmaz. Ortayı taşıma boruları doldurur."},{"t":"Ayrım","a":"Geniş öz tek çeneklidir.","d":"Eğer kökün ortasında geniş bir öz görülüyorsa bu tek çenekli bir köktür. Öz yoksa çift çeneklidir."}],"ans":"Ortada geniş öz varsa tek çenekli, öz küçük/yoksa çift çeneklidir"},{"q":"Tek çenekli bitki kökleri genellikle yıllar içinde pek kalınlaşmaz. Bu durum dikot köklerden nasıl bir farktır?","steps":[{"t":"Tek çenekli kök","a":"Çapı çok değişmez.","d":"Tek çenekli kökler yaşlandıkça genellikle belirgin şekilde kalınlaşmaz. İnce yapılarını korurlar."},{"t":"Çift çenekli kök","a":"Kalınlaşabilir.","d":"Çift çenekli kökler (özellikle ağaçlar) zamanla kalınlaşabilir. Çapları yıllar içinde artar."},{"t":"Fark","a":"Kalınlaşma yeteneği farklıdır.","d":"Tek çenekli kök çoğunlukla kalınlaşmaz, çift çenekli kök kalınlaşabilir. Bu, iki kök tipi arasındaki önemli bir farktır."}],"ans":"Tek çenekli kök genelde kalınlaşmaz; çift çenekli kök zamanla kalınlaşabilir"},{"q":"Tek çenekli bitki kökünde su emildikten sonra suyun ortadaki geniş özden değil de özün çevresindeki borulardan taşınması niçin mantıklıdır?","steps":[{"t":"Öz bölgesi","a":"Öz besin/dolgu içindir.","d":"Ortadaki geniş öz daha çok dolgu ve depo görevi yapar. Su taşıma görevi öze ait değildir."},{"t":"Borular","a":"Taşıma boruları özü çevreler.","d":"Su taşıyan borular özün çevresinde halka gibi dizilmiştir. Su bu borularla yukarıya iletilir."},{"t":"Mantık","a":"Her yapı görevine uygun.","d":"Su, taşımaya özelleşmiş borularla iletilirken öz farklı bir görev üstlenir. Böylece her bölge işine uygun çalışır."}],"ans":"Su, taşımaya özelleşmiş çevredeki borularla iletilir; öz dolgu/depo görevi gördüğü için su taşımaz"},{"q":"Saçak köklü bir tek çenekli bitki, kazık köklü bir bitkiye göre rüzgarlı havada toprağa tutunmada hangi avantaja sahip olabilir?","steps":[{"t":"Saçak kök","a":"Çok sayıda yüzeysel kök.","d":"Saçak kökte çok sayıda ince kök toprağın üst kısmına geniş bir ağ gibi yayılır. Bu kökler toprağı sıkıca sarar."},{"t":"Tutunma","a":"Geniş yüzey toprağı kavrar.","d":"Birçok kolun toprağı sarması, bitkiyi geniş bir alanda sabitler. Bu, üst toprağın kaymasını da azaltır."},{"t":"Avantaj","a":"Yüzeysel sağlam tutunma.","d":"Saçak kök, yüzeyde geniş alana yayıldığı için rüzgarda bitkiyi dengeli tutar. Özellikle üst toprağı tutmada etkilidir."}],"ans":"Çok sayıda kök toprağı geniş alanda sararak yüzeysel ve dengeli tutunma sağlar"},{"q":"Tek çenekli bir bitki kökünün enine kesitinde, su taşıyan boruların ortada toplanmak yerine bir halka gibi dizilmesi neyi gösterir?","steps":[{"t":"Boruların dizilişi","a":"Borular halka şeklinde.","d":"Tek çenekli kökte su ve besin boruları ortada toplanmaz, özün çevresinde halka gibi dizilir. Çok sayıda demet bulunur."},{"t":"Anlamı","a":"Geniş öz bırakır.","d":"Boruların kenara dizilmesi ortada geniş bir özün kalmasını sağlar. Bu, tek çenekli köke özgü bir düzendir."},{"t":"Sonuç","a":"Tek çenekli kök işaretidir.","d":"Halka şeklinde demet dizilişi ve geniş öz, kökün tek çenekli olduğunu gösterir. Bu özellik çift çenekliden ayırt ettirir."}],"ans":"Demetlerin halka şeklinde dizilip geniş öz bırakması, kökün tek çenekli olduğunu gösterir"}]},"ortaokul":{"kolay":[{"q":"Monokot (tek çenekli) kök enine kesitinde en dıştan içe doğru ilk üç tabaka nasıl sıralanır?","steps":[{"t":"En dış","a":"Epidermis bulunur.","d":"Monokot kökün en dışını tek sıra epidermis kaplar. Emici tüyleri de bu tabaka taşır."},{"t":"Orta","a":"Korteks gelir.","d":"Epidermisin altında geniş korteks yer alır. Bu bölge gevşek parankima hücrelerinden oluşur."},{"t":"İç sınır","a":"Endodermis bulunur.","d":"Korteksin en içinde endodermis tabakası vardır. Endodermis suyun merkeze geçişini denetler."}],"ans":"Epidermis, korteks, endodermis"},{"q":"Monokot kökte iletim demetleri (ksilem-floem grupları) nasıl dizilmiştir?","steps":[{"t":"Demet sayısı","a":"Çok sayıda demet vardır.","d":"Monokot kökte çok sayıda ksilem ve floem grubu bulunur. Bu demetler dikot köke göre daha fazladır."},{"t":"Diziliş","a":"Öz çevresinde halka yapar.","d":"Demetler merkezdeki özün çevresinde halka şeklinde dizilir. Ksilem ve floem nöbetleşe yerleşir."}],"ans":"Çok sayıda demet öz çevresinde halka şeklinde dizilir"},{"q":"Monokot kökte merkezde bulunan geniş bölgenin adı ve genel işlevi nedir?","steps":[{"t":"Bölge","a":"Merkezde öz vardır.","d":"Monokot kökün tam ortasında geniş bir öz (medulla) bulunur. Bu bölge belirgindir."},{"t":"İşlev","a":"Depo ve dolgu.","d":"Öz çoğunlukla parankima hücrelerinden oluşur ve besin depolayabilir. Ayrıca köke dolgunluk kazandırır."}],"ans":"Öz (medulla); besin depolama ve dolgu görevi görür"},{"q":"Çoğu monokot kök neden ikincil büyüme (kalınlaşma) yapamaz?","steps":[{"t":"Kambiyum durumu","a":"Sürekli kambiyum oluşmaz.","d":"Monokot kökte iletim demetleri arasında sürekli bir kambiyum (yanal meristem) oluşmaz. Kalınlaşma için bu doku gereklidir."},{"t":"Sonuç","a":"Kök ince kalır.","d":"Kambiyum olmadığı için kök çapça pek artmaz ve ince kalır. Bu nedenle monokot kökler genellikle ikincil büyüme yapamaz."}],"ans":"İletim demetleri arasında kambiyum oluşmadığı için kalınlaşamaz"},{"q":"Monokot kökte endodermis tabakasının görevi nedir?","steps":[{"t":"Yeri","a":"Korteks ile merkez arasında.","d":"Endodermis, korteksin en iç sırasıdır ve merkezi silindiri sarar. Tek sıra hücreden oluşur."},{"t":"Görevi","a":"Su geçişini denetler.","d":"Endodermis, Kaspari şeridi sayesinde suyun merkeze geçişini denetler. Böylece seçici madde alımı sağlanır."}],"ans":"Suyun merkezi silindire geçişini denetlemek (Kaspari şeridi ile)"}],"zor":[{"q":"Monokot kök ile dikot kökü iletim demetlerinin diziliş ve sayısı bakımından karşılaştırınız.","steps":[{"t":"Monokot demetleri","a":"Çok sayıda, halka şeklinde.","d":"Monokot kökte çok sayıda ksilem-floem demeti öz çevresinde halka gibi dizilir. Bu nedenle poliark (çok kollu) denir."},{"t":"Dikot demetleri","a":"Az sayıda, merkezde radyal.","d":"Dikot kökte demetler azdır; ksilem merkezde yıldız şeklinde, floem aralarda yer alır. Buna radyal diziliş denir."},{"t":"Karşılaştırma","a":"Diziliş ve sayı farklı.","d":"Monokotta çok sayıda demet halka yapar ve geniş öz kalır; dikotta az demet merkezde toplanır ve öz küçüktür. Bu, iki kök tipinin temel ayrımıdır."}],"ans":"Monokotta çok sayıda demet halka şeklinde (geniş öz); dikotta az demet merkezde radyal (küçük öz)"},{"q":"Monokot kökte geniş öz bölgesinin bulunması bitkinin işlevsel ihtiyaçlarıyla nasıl bağdaşır?","steps":[{"t":"Özün işlevi","a":"Depo ve mekanik destek.","d":"Geniş öz besin depolayabilir ve köke dolgunluk vererek mekanik destek sağlar. Su tutumuna da katkıda bulunabilir."},{"t":"Demet konumu","a":"Demetler çevrede etkin çalışır.","d":"İletim demetleri özün çevresinde halka yaptığından su ve besin çevre boyunca verimli iletilir. Merkez taşıma için zorunlu değildir."},{"t":"Bağdaşma","a":"İhtiyaca uygun yapı.","d":"Monokot bitkiler genelde tek yıllık veya otsu olduğundan kalınlaşmaya değil verimli iletim ve depolamaya ihtiyaç duyar. Geniş öz ve halka demet bu ihtiyaçla uyumludur."}],"ans":"Geniş öz depolama ve destek sağlar; çevredeki halka demetler verimli iletim yapar, bu otsu monokota uygundur"},{"q":"Monokot kökte de Kaspari şeridi bulunur. Bu şeridin suyun seçici alımındaki rolünü açıklayınız.","steps":[{"t":"Apoplast yolu","a":"Su çeperden ilerler.","d":"Korteksten gelen su başlangıçta hücre çeperleri arasından (apoplast) serbestçe ilerler. Bu yolda seçicilik azdır."},{"t":"Kaspari engeli","a":"Su geçirmez kuşak durdurur.","d":"Endodermiste Kaspari şeridi süberin içerdiğinden apoplast yolunu keser. Su artık çeperden geçemez."},{"t":"Sonuç","a":"Su zardan geçer, denetlenir.","d":"Su endodermis hücre zarından geçmek zorunda kalır ve böylece giren maddeler seçilir. Bu mekanizma monokotta da dikottaki gibi çalışır."}],"ans":"Kaspari şeridi apoplast yolunu kesip suyu hücre zarından geçmeye zorlar, böylece seçici alım sağlanır"},{"q":"Bir kök kesitinde \"çok sayıda ksilem-floem demeti halka şeklinde ve geniş öz\" görülüyorsa bu kökün tipi nedir ve neden?","steps":[{"t":"Gözlem","a":"Halka demet, geniş öz.","d":"Kesitte çok sayıda iletim demeti merkezdeki geniş özün çevresinde halka yapar. Öz belirgin ve geniştir."},{"t":"Karşılaştırma","a":"Dikotta öz küçük, demet az.","d":"Dikot kökte demet azdır, merkezde radyal dizilir ve öz küçüktür. Buradaki görünüm dikota uymaz."},{"t":"Sonuç","a":"Bu bir monokot köktür.","d":"Çok sayıda halka demet ve geniş öz monokot kökün belirgin özelliğidir. Bu nedenle incelenen kök monokottur."}],"ans":"Monokot kök; çok sayıda halka demet + geniş öz monokota özgüdür"},{"q":"Monokot kökün ikincil büyüme yapamamasının, bitkinin yaşam süresi ve büyüklüğü üzerindeki olası etkisi nedir?","steps":[{"t":"Kalınlaşma yokluğu","a":"Kök çapı pek artmaz.","d":"Monokot kökte kambiyum olmadığından kök kalınlaşamaz. Bu yüzden köteki destek ve iletim kapasitesi sınırlı kalır."},{"t":"Etki","a":"Genelde otsu ve kısa ömürlü.","d":"Kalınlaşamayan kök büyük odunsu gövdeyi taşımakta zorlanır. Bu nedenle çoğu monokot otsu, tek veya az yıllık kalır."},{"t":"İstisna","a":"Bazı monokotlar farklı çözüm bulur.","d":"Palmiye gibi bazı monokotlar gövdede farklı yollarla destek sağlasa da klasik kambiyumlu kalınlaşma yapmazlar. Genel eğilim sınırlı büyüklük ve otsu yapıdır."}],"ans":"Kök kalınlaşamadığı için monokotlar genelde otsu, sınırlı büyüklükte ve çoğunlukla kısa ömürlü kalır"}]},"lise":{"kolay":[{"q":"Monokot kök enine kesitinde en dıştan merkeze doğru ana doku ve bölgelerin sırasını yazınız.","steps":[{"t":"Dış bölge","a":"Epidermis ve emici tüyler.","d":"En dışta tek sıra epidermis ve emici tüyler bulunur. Bu bölge su ve mineral emer."},{"t":"Korteks ve sınır","a":"Korteks ve endodermis.","d":"Epidermisin altında geniş korteks, onun en içinde Kaspari şeritli endodermis yer alır. Endodermis geçişi denetler."},{"t":"Merkez","a":"Perisikl, halka demetler, geniş öz.","d":"Endodermisin içinde perisikl, çevrede halka dizilmiş çok sayıda ksilem-floem demeti ve merkezde geniş öz bulunur. Öz monokotta belirgindir."}],"ans":"Epidermis (+tüy) → korteks → endodermis → perisikl → halka şeklinde çok sayıda ksilem-floem → geniş öz"},{"q":"Monokot kökte iletim demetlerinin sayısı ve dizilişi nasıldır, buna ne ad verilir?","steps":[{"t":"Sayı","a":"Çok sayıda demet vardır.","d":"Monokot kökte ksilem ve floem grupları çok sayıdadır (genellikle altıdan fazla). Bu çoklu yapı dikottan ayırt ettirir."},{"t":"Diziliş","a":"Halka şeklinde dizilir.","d":"Demetler özün çevresinde radyal halka yapar; ksilem ve floem nöbetleşe yer alır. Çok kollu olmaları nedeniyle poliark denir."}],"ans":"Çok sayıda demet öz çevresinde halka şeklinde radyal dizilir; buna poliark denir"},{"q":"Monokot kökte öz (medulla) bölgesinin yapısı ve işlevini açıklayınız.","steps":[{"t":"Yapısı","a":"Geniş parankima bölgesi.","d":"Monokot kökün merkezindeki öz, ince çeperli parankima hücrelerinden oluşan geniş bir bölgedir. İletim demetlerinin iç tarafında kalır."},{"t":"İşlevi","a":"Depo ve destek.","d":"Öz besin (genellikle nişasta) depolar ve köke dolgunluk vererek mekanik destek sağlar. Su tutumuna da katkıda bulunur."}],"ans":"Geniş parankimadan oluşur; besin depolama ve mekanik destek sağlar"},{"q":"Monokot kökte endodermis ve Kaspari şeridinin yapısını ve görevini açıklayınız.","steps":[{"t":"Endodermis","a":"Korteksin iç sırası.","d":"Endodermis, korteks ile merkezi silindir arasındaki tek sıra hücredir. Suyun seçici geçişini sağlayan sınırdır."},{"t":"Kaspari şeridi","a":"Süberinli su geçirmez kuşak.","d":"Endodermis hücrelerinin radyal ve enine çeperlerinde süberin içeren Kaspari şeridi bulunur. Bu kuşak apoplast yolunu keser."},{"t":"Görev","a":"Denetimli su geçişi.","d":"Kaspari şeridi suyu simplast yoluna zorlar ve böylece bitki giren maddeleri seçer. Monokot kökte bu yapı kalın çeperli olarak çok belirgindir."}],"ans":"Endodermis denetleyici sınırdır; Kaspari şeridi apoplastı kesip suyu simplasta zorlar, monokotta belirgindir"},{"q":"Monokot kökün ikincil büyüme yapamamasının dokusal nedeni nedir?","steps":[{"t":"Kambiyum yokluğu","a":"Sürekli yanal meristem oluşmaz.","d":"Monokot kökte iletim demetleri kapalı tiptedir ve aralarında sürekli bir kambiyum oluşmaz. Yanal meristem olmadan kalınlaşma sağlanamaz."},{"t":"Sonuç","a":"Kök ince kalır.","d":"Kambiyum bulunmadığı için ikincil ksilem ve floem üretilemez ve kök çapı pek artmaz. Bu nedenle monokot kökler genellikle ikincil büyüme yapamaz."}],"ans":"İletim demetleri kapalı olup aralarında kambiyum (yanal meristem) oluşmadığı için ikincil büyüme olmaz"},{"q":"Monokot kökte korteks bölgesinin yapısı ve işlevleri nelerdir?","steps":[{"t":"Yapısı","a":"Geniş gevşek parankima.","d":"Monokot kökte korteks geniş ve gevşek parankima hücrelerinden oluşur. Hücreler arası boşluklar bulunur."},{"t":"İşlevleri","a":"İletim, depo, gaz değişimi.","d":"Korteks emilen suyu endodermise iletir, besin depolar ve boşlukları sayesinde gaz alışverişini kolaylaştırır. Sulak ortam monokotlarında havalandırma dokusu (aerenkima) da oluşabilir."}],"ans":"Geniş gevşek parankimadır; su iletimi, depolama ve gaz değişimini (aerenkima) sağlar"},{"q":"Monokot kökte perisiklin yeri ve görevi nedir?","steps":[{"t":"Yeri","a":"Endodermisin iç tarafında.","d":"Perisikl, endodermisin hemen içinde merkezi silindiri saran ince tabakadır. İletim demetlerini çevreler."},{"t":"Görevi","a":"Yan kök oluşturur.","d":"Perisikl hücreleri bölünerek yan kökleri başlatır. Monokotta ikincil büyüme sınırlı olsa da yan kök oluşumu perisiklten gerçekleşir."}],"ans":"Endodermisin içinde yer alır; yan (lateral) köklerin oluşumunu sağlar"},{"q":"Monokot kök ile dikot kökü öz bölgesi bakımından karşılaştırınız.","steps":[{"t":"Monokot öz","a":"Geniş ve belirgin.","d":"Monokot kökte merkezde geniş bir öz bulunur. İletim demetleri bu özün çevresinde halka yapar."},{"t":"Dikot öz","a":"Küçük veya yok.","d":"Dikot kökte merkezi ksilem doldurduğundan öz çok küçüktür ya da yoktur. Merkez büyük ölçüde iletim dokusu ile kaplıdır."}],"ans":"Monokotta öz geniş/belirgin, dikotta küçük/yoktur"},{"q":"Monokot kökte iletim demetlerinin \"poliark\" olması ne anlama gelir?","steps":[{"t":"Poliark kavramı","a":"Çok sayıda protoksilem kolu.","d":"Poliark, kökte çok sayıda (genellikle altıdan fazla) protoksilem kolu bulunması anlamına gelir. Bu, çok sayıda ksilem grubunu ifade eder."},{"t":"Monokottaki durum","a":"Demetler çoktur, halka yapar.","d":"Monokot kökte demet sayısı yüksek olduğundan poliark yapı görülür. Demetler özün çevresinde halka şeklinde dizilir."}],"ans":"Çok sayıda (genelde altıdan fazla) protoksilem kolu/ksilem grubu bulunması demektir"},{"q":"Monokot kökte ksilem ve floemin enine kesitteki birbirine göre konumu nasıldır?","steps":[{"t":"Diziliş ilkesi","a":"Radyal (nöbetleşe).","d":"Monokot kökte ksilem ve floem ayrı gruplar halinde, yarıçap boyunca nöbetleşe dizilir. Aynı hatta üst üste değil, dönüşümlü yer alırlar."},{"t":"Halka düzeni","a":"Öz çevresinde sıralanır.","d":"Çok sayıda ksilem ve floem grubu özün çevresinde bir halka oluşturur. Ksilem genelde içte, floem dışta hizalanır."}],"ans":"Ksilem ve floem öz çevresinde halka boyunca radyal (nöbetleşe) dizilir; ksilem içte, floem dışta"},{"q":"Monokot kökte emici tüylerin yapısı ve emilimdeki rolünü açıklayınız.","steps":[{"t":"Yapısı","a":"Epidermis hücre uzantısı.","d":"Emici tüyler, epidermis hücrelerinin tek hücreli ince uzantılarıdır. Toprak taneleri arasına girerek temas yüzeyini artırır."},{"t":"Rolü","a":"Su ve mineral emilimi.","d":"Bu tüyler topraktan su ve mineral emiliminin büyük kısmını yapar. Geniş yüzey emilimi en üst düzeye çıkarır."}],"ans":"Epidermisin yüzey artıran uzantılarıdır; su ve mineral emiliminin asıl yapıldığı yapılardır"},{"q":"Monokot kökte saçak kök sisteminin avantajları nelerdir?","steps":[{"t":"Saçak kök","a":"Çok sayıda eşit ince kök.","d":"Monokotlarda ana kök erken gerileyip yerine gövde tabanından çıkan çok sayıda ince adventif kök gelişir. Buna saçak kök denir."},{"t":"Avantaj","a":"Geniş yüzeysel tutunma.","d":"Saçak kök üst toprağa geniş bir ağ gibi yayılır; toprağı tutar, erozyonu azaltır ve yüzeydeki suyu hızlı emer. Bu, otsu monokotlar için işlevseldir."}],"ans":"Çok sayıda kök geniş yüzeyi sararak güçlü tutunma, erozyon önleme ve hızlı yüzey su emilimi sağlar"},{"q":"Monokot kökte merkezi silindir (stel) hangi yapıları kapsar?","steps":[{"t":"Sınır","a":"Endodermisin içi.","d":"Merkezi silindir, endodermisin iç tarafında kalan tüm dokuları kapsar. Buna stel denir."},{"t":"İçeriği","a":"Perisikl, halka demetler, geniş öz.","d":"Monokotta merkezi silindir; perisikli, halka şeklinde çok sayıda ksilem-floem demetini ve geniş özü içerir. Geniş öz monokot steline özgü bir özelliktir."}],"ans":"Perisikl, halka şeklinde çok sayıda ksilem-floem ve geniş özü kapsar"},{"q":"Monokot kökte endodermis hücrelerinin zamanla \"U\" veya nal şeklinde kalınlaşması ne anlama gelir?","steps":[{"t":"Kalınlaşma","a":"İç ve yan çeperler kalınlaşır.","d":"Monokot kökte endodermis hücrelerinin iç (merkeze bakan) ve yan çeperleri süberin/lignin ile kalınlaşır. Dış çeper ince kalır, böylece kesitte nal/U görünümü oluşur."},{"t":"Anlamı","a":"İleri düzeyde geçiş denetimi.","d":"Bu kalınlaşma, suyun yalnızca belirli ince çeperli geçit hücrelerinden geçmesini sağlar. Böylece olgun monokot kökte madde alımı daha sıkı denetlenir."}],"ans":"Endodermisin iç/yan çeperlerinin süberinleşip nal şeklinde kalınlaşmasıdır; geçişi geçit hücrelerine sınırlayarak denetimi artırır"},{"q":"Monokot kökte geçit hücrelerinin (passage cells) konumu ve işlevi nedir?","steps":[{"t":"Geçit hücresi","a":"İnce çeperli endodermis hücresi.","d":"Monokot kökte endodermis nal şeklinde kalınlaşırken bazı hücreler ince çeperli kalır. Bunlara geçit hücreleri denir."},{"t":"Konum","a":"Protoksilem hizasında.","d":"Geçit hücreleri genellikle protoksilem kollarının karşısında yer alır. Bu konum su girişini iletim demetlerine yönlendirir."},{"t":"İşlev","a":"Su girişini sürdürür.","d":"Kalın çeperli endodermiste bile geçit hücreleri suyun ve iyonların merkezi silindire girmesini sağlar. Böylece iletim kesintiye uğramaz."}],"ans":"Protoksilem hizasındaki ince çeperli geçit hücreleri, kalınlaşmış endodermiste su ve iyon girişini sürdürür"}],"zor":[{"q":"Monokot kökün ikincil büyüme yapamamasını, dikot kökteki kambiyum oluşumuyla karşılaştırarak dokusal düzeyde açıklayınız.","steps":[{"t":"Dikotta kambiyum","a":"Ksilem-floem arası bölünür.","d":"Dikot kökte ksilem ile floem arasındaki parankima hücreleri ve perisiklin bir kısmı bölünme kazanarak demet kambiyumu oluşturur. Bu sürekli yanal meristem kalınlaşmayı başlatır."},{"t":"Monokotta durum","a":"Demetler kapalı, ara hücre yok.","d":"Monokot kökte demetler kapalı tiptedir ve ksilem-floem arasında bölünebilen sürekli bir hücre tabakası bulunmaz. Bu yüzden kambiyum halkası oluşamaz."},{"t":"Sonuç farkı","a":"Dikot kalınlaşır, monokot kalmaz.","d":"Kambiyum üreten dikot kök içe ikincil ksilem, dışa ikincil floem üreterek kalınlaşır. Monokot kökte bu üretim olmadığı için çap sabit kalır ve ikincil büyüme görülmez."}],"ans":"Dikotta ksilem-floem arası kambiyum oluşup ikincil doku üretir; monokotta demetler kapalı, kambiyum oluşmaz, bu yüzden kalınlaşmaz"},{"q":"Monokot kökte geniş özün ve poliark iletim yapısının, otsu ve hızlı büyüyen yaşam stratejisiyle uyumunu açıklayınız.","steps":[{"t":"Geniş öz","a":"Depolama ve hafif destek.","d":"Geniş öz besin depolar ve köke turgorla destek verir, ancak yoğun odun gerektirmez. Bu, hafif ve hızlı kurulabilen bir yapıdır."},{"t":"Poliark iletim","a":"Çevrede verimli su-besin akışı.","d":"Çok sayıda demetin çevrede halka yapması, su ve besinin geniş kesit boyunca verimli iletilmesini sağlar. Hızlı büyüyen otsu bitki yüksek iletim kapasitesi kazanır."},{"t":"Strateji uyumu","a":"Hızlı, ucuz, kalınlaşmasız.","d":"Monokotlar genelde tek yıllık veya otsu olduğundan pahalı odunsu kalınlaşmaya değil hızlı kuruluma ihtiyaç duyar. Geniş öz ve poliark yapı bu hızlı, ucuz büyüme stratejisiyle uyumludur."}],"ans":"Geniş öz ucuz depolama/destek, poliark demet verimli iletim sağlar; bu kalınlaşmasız, hızlı otsu büyümeye uygundur"},{"q":"Monokot kökte suyun topraktan ksileme ulaşana kadar izlediği yolu, geçtiği doku ve engellerle sırasıyla açıklayınız.","steps":[{"t":"Emilim","a":"Su emici tüyle alınır.","d":"Su, olgunlaşma bölgesindeki emici tüylerle topraktan emilir. Yüksek yüzey emilimi artırır."},{"t":"Korteks","a":"Su korteksten ilerler.","d":"Su geniş korteksten apoplast ve simplast yollarıyla iç kesime doğru ilerler. Bu aşamada seçicilik henüz azdır."},{"t":"Endodermis","a":"Kaspari/geçit hücresi denetler.","d":"Endodermiste Kaspari şeridi apoplastı keser; monokotta nal şeklinde kalınlaşma nedeniyle su özellikle geçit hücrelerinden simplasta geçer. Böylece denetim sağlanır."},{"t":"Ksileme ulaşma","a":"Su perisiklten ksileme varır.","d":"Su perisikli geçerek halka demetlerindeki ksileme ulaşır. Ksilem suyu kohezyon-gerilim ile yukarı taşır."}],"ans":"Emici tüy → korteks → endodermis (Kaspari + geçit hücreleri ile simplasta zorlanır) → perisikl → halka demetlerindeki ksilem"},{"q":"Monokot kökte protoksilem ve metaksilemin konumunu (ekzark gelişim) ve poliark yapı ile ilişkisini açıklayınız.","steps":[{"t":"Protoksilem","a":"Dış kenarda, ilk oluşan.","d":"Protoksilem kökte dış kenarda yer alır ve ilk olgunlaşan dar çaplı ksilemdir. Halkalı/sarmal çeper kalınlaşması gösterir."},{"t":"Metaksilem","a":"İçte, geniş çaplı.","d":"Metaksilem merkeze daha yakın ve geniş çaplıdır, daha sonra olgunlaşır. Daha çok su iletir."},{"t":"Ekzark + poliark","a":"Dıştan içe, çok kollu.","d":"Kökte olgunlaşma dıştan içe (ekzark) olur. Monokotta çok sayıda protoksilem kolu bulunduğundan yapı hem ekzark hem poliarktır."}],"ans":"Protoksilem dışta/dar, metaksilem içte/geniş; kökte ekzark gelişim görülür ve monokotta çok kollu (poliark) olur"},{"q":"Sulak ortamda yetişen monokot bitkilerin (örneğin çeltik) kökünde gözlenen aerenkima dokusunun işlevini açıklayınız.","steps":[{"t":"Aerenkima","a":"Geniş hava boşluklu doku.","d":"Aerenkima, korteks parankimasında geniş hava boşlukları içeren özelleşmiş bir dokudur. Hücreler arasında geniş kanallar bulunur."},{"t":"Oluşum nedeni","a":"Su altında oksijen azdır.","d":"Sulak topraklarda kök çevresinde oksijen çok düşüktür. Bitki gövdeden köke oksijen ulaştırmak için hava kanallarına ihtiyaç duyar."},{"t":"İşlev","a":"Oksijeni köke iletir.","d":"Aerenkima kanalları, yapraktan ve gövdeden alınan oksijeni su altındaki köke iletir. Böylece kök hücreleri oksijensiz ortamda bile solunum yapabilir."}],"ans":"Aerenkima geniş hava kanallarıyla gövdeden köke oksijen ileterek su altındaki kökün solunumunu sağlar"},{"q":"Monokot kökte endodermisin nal şeklinde kalınlaşması ile dikot kökte endodermisin daha çok Kaspari şeridiyle sınırlı kalması arasındaki işlevsel farkı açıklayınız.","steps":[{"t":"Dikot endodermisi","a":"Çoğunlukla Kaspari şeridi.","d":"Dikot kökte endodermis genellikle yan çeperlerdeki Kaspari şeridi ile denetim sağlar; ikincil büyümeyle endodermis yerini perideme bırakabilir. Aşırı çeper kalınlaşması belirgin değildir."},{"t":"Monokot endodermisi","a":"İç/yan çeperler kalınlaşır.","d":"Monokot kökte endodermis nal şeklinde süberin/lignin ile kalınlaşır ve uzun ömürlü kalır. Çünkü ikincil büyüme olmadığından bu sınır kalıcı korumayı üstlenir."},{"t":"İşlevsel fark","a":"Kalıcı vs geçici denetim.","d":"Monokotta kalınlaşmış endodermis kalıcı ve sıkı bir geçiş denetimi sağlarken dikotta endodermisin rolü ikincil büyümeyle azalabilir. Bu fark iki kökün büyüme stratejisini yansıtır."}],"ans":"Monokotta nal şeklinde kalınlaşan endodermis kalıcı sıkı denetim yapar; dikotta Kaspari ile sınırlı endodermisin rolü ikincil büyümeyle azalır"},{"q":"Monokot kökte yan köklerin perisiklten endojen oluşumunu ve halka demet yapısıyla iletim bağlantısını açıklayınız.","steps":[{"t":"Endojen oluşum","a":"Yan kök perisiklten çıkar.","d":"Yan kökler perisikl hücrelerinin bölünmesiyle iç dokudan başlar. Korteks ve epidermisi yararak dışa çıkar."},{"t":"Bağlantı","a":"Demetlere bağlanır.","d":"Perisikl halka şeklindeki iletim demetlerinin hemen dışında olduğundan yeni yan kökün ksilem-floemi ana kökün demetlerine bağlanır. Bu su-besin sürekliliğini sağlar."},{"t":"İşlev","a":"Bütünleşik iletim ağı.","d":"Bu sayede çok sayıda yan kök, ana kökün poliark iletim sistemine doğrudan bağlanır. Sonuçta saçak kök sisteminde kesintisiz ve dağıtılmış bir iletim ağı oluşur."}],"ans":"Yan kök perisiklten endojen oluşup halka demetlere bağlanır; böylece saçak kökte kesintisiz, dağıtılmış iletim ağı kurulur"},{"q":"Monokot kök kesitinde demet sayısının dikot köke göre çok fazla olması, su iletim kapasitesi açısından ne sağlar?","steps":[{"t":"Demet sayısı","a":"Monokotta çok demet var.","d":"Monokot kökte çok sayıda ksilem grubu öz çevresinde halka yapar. Bu, çok sayıda paralel su yolu demektir."},{"t":"Kapasite","a":"Paralel yollar iletimi artırır.","d":"Çok sayıda paralel ksilem kanalı, toplam su iletim kesitini artırır. Böylece kök birim zamanda daha fazla su taşıyabilir."},{"t":"Strateji","a":"Hızlı büyümeye uygun.","d":"Yüksek iletim kapasitesi, hızlı büyüyen otsu monokotların yüksek terleme ve su talebini karşılar. Bu, kalınlaşma olmadan iletimi yeterli kılar."}],"ans":"Çok sayıda paralel ksilem demeti toplam iletim kesitini artırır, hızlı büyüyen otsu bitkinin yüksek su talebini karşılar"},{"q":"Monokot kökte korteksin geniş olmasının, kuraklık ve depolama açısından olası avantajlarını açıklayınız.","steps":[{"t":"Geniş korteks","a":"Çok sayıda parankima hücresi.","d":"Monokot kökte korteks geniş ve çok hücrelidir. Bu hücreler su ve besin tutabilir."},{"t":"Depolama","a":"Nişasta/besin biriktirir.","d":"Geniş korteks ve öz, nişasta gibi besinleri ve bir miktar suyu depolayabilir. Bu, zor dönemler için yedek sağlar."},{"t":"Kuraklık avantajı","a":"Su tamponu görevi.","d":"Depolanan su ve besin, kısa süreli kuraklıkta bitkiye tampon sağlar. Böylece kök hücreleri bir süre dayanabilir ve büyüme sürebilir."}],"ans":"Geniş korteks/öz besin ve su depolayarak kuraklıkta tampon ve yedek enerji sağlar"},{"q":"Monokot ve dikot köklerini bir bütün olarak (epidermis, korteks, endodermis, demet dizilişi, öz, ikincil büyüme) karşılaştırınız.","steps":[{"t":"Ortak yapılar","a":"Dış üç tabaka benzer.","d":"Her iki kökte de epidermis (emici tüylü), korteks ve Kaspari şeritli endodermis bulunur. Su emilim ve denetim mekanizmaları benzerdir."},{"t":"Demet ve öz farkı","a":"Diziliş ve öz farklı.","d":"Dikotta az sayıda demet merkezde radyal dizilir ve öz küçüktür/yoktur; monokotta çok sayıda demet halka yapar ve öz geniştir. Bu en belirgin ayrımdır."},{"t":"İkincil büyüme","a":"Dikot kalınlaşır.","d":"Dikotta ksilem-floem arası kambiyum oluşup ikincil büyüme görülür; monokotta kambiyum oluşmadığından kök ince kalır. Bu, yaşam stratejisi farkını yansıtır."}],"ans":"Dış üç tabaka benzer; dikotta az demet/küçük öz/ikincil büyüme var, monokotta çok demet/geniş öz/ikincil büyüme yok"},{"q":"Monokot kökte iletim demetlerinin \"kapalı demet\" olması terimi neyi ifade eder ve ikincil büyümeyle ilişkisi nedir?","steps":[{"t":"Kapalı demet","a":"Ksilem-floem arası kambiyumsuz.","d":"Kapalı demet, ksilem ile floem arasında bölünebilen kambiyum bulunmayan demet tipidir. Demet, oluştuktan sonra çapça büyüyemez."},{"t":"Açık demet farkı","a":"Dikotta kambiyum vardır.","d":"Dikotta demetler açık tiptedir; ksilem-floem arasında kambiyum bulunur ve kalınlaşma sağlar. Monokot demetinde bu kambiyum yoktur."},{"t":"İlişki","a":"Kapalı demet = ikincil büyüme yok.","d":"Demetler kapalı olduğundan monokot kökte ikincil büyüme gerçekleşmez. Bu yüzden monokot kök ince ve sabit çaplı kalır."}],"ans":"Kapalı demet, ksilem-floem arası kambiyum içermeyen demettir; bu nedenle monokot kök ikincil büyüme yapamaz"},{"q":"Monokot kökte suyun apoplast yolundan simplast yoluna geçişinin, nal şeklinde kalınlaşmış endodermis nedeniyle nasıl zorunlu hale geldiğini açıklayınız.","steps":[{"t":"Apoplast giriş","a":"Su çeperden ilerler.","d":"Korteksten gelen su öncelikle hücre çeperleri arasından (apoplast) serbestçe ilerler. Bu yol seçici değildir."},{"t":"Kalın çeper engeli","a":"Nal kalınlaşma yolu kapatır.","d":"Monokot endodermisinde iç ve yan çeperler süberin/lignin ile nal şeklinde kalınlaşır. Bu kalın çeperler apoplast yolunu büyük ölçüde kapatır."},{"t":"Simplasta geçiş","a":"Su geçit hücresinden içeri girer.","d":"Su, ince çeperli geçit hücrelerinin zarından geçerek simplasta girmek zorunda kalır. Böylece su mecburen hücre denetiminden geçer."},{"t":"Sonuç","a":"Sıkı seçici alım.","d":"Bu zorunlu simplast geçişi, monokot kökte madde alımının çok sıkı denetlenmesini sağlar. İstenmeyen iyonların girişi önemli ölçüde sınırlanır."}],"ans":"Nal şeklinde kalınlaşan çeperler apoplastı kapatır, su ince çeperli geçit hücrelerinden simplasta geçmek zorunda kalır; böylece sıkı seçici alım sağlanır"},{"q":"Monokot kökte su potansiyeli farkı kullanılarak suyun topraktan emici tüye ve korteks hücrelerine doğru ilerleyişini açıklayınız.","steps":[{"t":"Temel ilke","a":"Su düşük potansiyele akar.","d":"Su, su potansiyeli yüksek bölgeden düşük bölgeye doğru osmozla hareket eder. Bu, kökte su girişinin temelidir."},{"t":"Topraktan tüye","a":"Tüy içi daha düşük potansiyellidir.","d":"Emici tüy hücresinde çözünmüş madde çok olduğundan su potansiyeli topraktan düşüktür. Bu nedenle su topraktan tüye girer."},{"t":"Hücreler arası akış","a":"Basamaklı potansiyel düşüşü.","d":"Tüyden korteks hücrelerine ve endodermise doğru su potansiyeli giderek azalır. Bu basamaklı düşüş suyun sürekli merkeze akmasını sağlar."}],"ans":"Su, yüksek potansiyelli topraktan giderek azalan potansiyelli tüy ve korteks hücrelerine osmozla ilerler"},{"q":"Monokot kök ile dikot kökün enine kesit fotoğrafları verildiğinde, ikisini ayırt etmede kullanılabilecek en güvenilir üç ölçütü açıklayınız.","steps":[{"t":"Ölçüt 1","a":"Öz büyüklüğü.","d":"Geniş ve belirgin öz monokotu, küçük veya yok denecek öz dikotu gösterir. Öz büyüklüğü hızlı ve güvenilir bir ipucudur."},{"t":"Ölçüt 2","a":"Demet sayısı ve diziliş.","d":"Çok sayıda demetin halka şeklinde dizilmesi (poliark) monokotu; az sayıda demetin merkezde radyal (yıldız) dizilmesi dikotu gösterir."},{"t":"Ölçüt 3","a":"Ksilem şekli.","d":"Dikotta merkezde yıldız/çarpı şeklinde ksilem görülür; monokotta ksilem grupları halka boyunca ayrı ayrı dizilir, merkezde yıldız ksilem yoktur. Bu şekil farkı ayrımı pekiştirir."}],"ans":"Öz büyüklüğü (monokot geniş/dikot küçük), demet sayısı-dizilişi (poliark halka/radyal) ve ksilem şekli (monokot dağınık/dikot merkezde yıldız)"},{"q":"Monokot kökte halka şeklinde dizilmiş çok sayıda demetin, kökün mekanik dayanıklılığına ve esnekliğine katkısını açıklayınız.","steps":[{"t":"Demet dağılımı","a":"Lignili demetler çevreye yayılı.","d":"Monokot kökte lignin içeren ksilem demetleri çevrede halka boyunca dağılmıştır. Bu, sertliği tek bir merkez yerine geniş bir çembere yayar."},{"t":"Mekanik etki","a":"Bükülmeye karşı destek.","d":"Çevreye dağılmış sert demetler, kökün eğilme ve bükülme kuvvetlerine karşı direncini artırır. Çember düzeni mekanik açıdan verimlidir."},{"t":"Esneklik","a":"Geniş öz esneklik sağlar.","d":"Merkezdeki yumuşak öz, köke bir miktar esneklik kazandırır ve ani kuvvetlerde kırılma yerine bükülmeyi sağlar. Böylece sert çember ile esnek merkez birlikte dayanıklılık verir."}],"ans":"Çevreye dağılmış sert demetler bükülme direncini artırır, yumuşak geniş öz esneklik sağlar; birlikte dayanıklı ve esnek bir kök oluştururlar"}]}}};
